{
  "name": "Level Up Life - RPG Habit Tracker",
  "description": "A gamified habit tracker that lets you visualize your progress as RPG stats. Complete habits to gain XP, level up, and generate your custom avatar using Gemini AI."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type StatType = 'STR' | 'INT' | 'VIT' | 'DEX' | 'CHR';

export const STAT_LABELS: Record<StatType, string> = {
  STR: '力量 (Strength)',
  INT: '智力 (Intelligence)',
  VIT: '體力 (Vitality)',
  DEX: '敏捷 (Dexterity)',
  CHR: '魅力 (Charisma)',
};

export interface Habit {
  id: string;
  title: string;
  description?: string;
  stat: StatType;
  xpReward: number;
  statReward: number;
  completedDates: string[]; // ISO date strings YYYY-MM-DD
  streak: number;
}

export interface UserStats {
  level: number;
  currentXp: number;
  nextLevelXp: number;
  attributes: Record<StatType, number>;
}

export interface ImageConfig {
  aspectRatio: string;
  imageSize: string;
}

import { GoogleGenAI } from "@google/genai";

// Helper to get the AI client, ensuring we use the latest key if refreshed
const getAiClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export interface GenerateAvatarParams {
  prompt: string;
  aspectRatio: string;
  imageSize: string; // "1K", "2K", "4K"
}

export const generateAvatarImage = async (params: GenerateAvatarParams): Promise<string> => {
  const ai = getAiClient();

  try {
    // Using the specific model requested: gemini-3-pro-image-preview
    // This model supports image generation via generateContent with specific configs
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [
          {
            text: params.prompt,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: params.aspectRatio,
          imageSize: params.imageSize,
        },
      },
    });

    // Extract image from response
    // The response structure for image gen usually contains inlineData in the parts
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        const base64EncodeString = part.inlineData.data;
        const mimeType = part.inlineData.mimeType || 'image/png';
        return `data:${mimeType};base64,${base64EncodeString}`;
      }
    }

    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Gemini Image Gen Error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Key, ExternalLink } from 'lucide-react';

interface ApiKeySelectorProps {
  onKeySelected: () => void;
}

// Extend window interface to include aistudio helper
declare global {
  interface Window {
    aistudio?: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

export const ApiKeySelector: React.FC<ApiKeySelectorProps> = ({ onKeySelected }) => {
  const [hasKey, setHasKey] = useState<boolean>(false);
  const [loading, setLoading] = useState<boolean>(true);

  const checkKey = async () => {
    if (window.aistudio?.hasSelectedApiKey) {
      const selected = await window.aistudio.hasSelectedApiKey();
      setHasKey(selected);
      if (selected) {
        onKeySelected();
      }
    } else {
      // Fallback for dev environments where window.aistudio might not be injected
      // In a real scenario with the specific proxy, this wouldn't happen, 
      // but for safety we default to true if the API_KEY env is present.
      if (process.env.API_KEY) {
        setHasKey(true);
        onKeySelected();
      }
    }
    setLoading(false);
  };

  useEffect(() => {
    checkKey();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio?.openSelectKey) {
      try {
        await window.aistudio.openSelectKey();
        // Immediately check after selection attempt
        await checkKey();
        // Force a reload might be needed in some environments, but here we try to just update state
        // If the implementation requires a reload to inject the key into process.env, the user might need to refresh manually,
        // but typically the proxy handles it. We will assume success if no error.
        onKeySelected(); 
      } catch (error) {
        console.error("Key selection failed", error);
        // Reset state
        setHasKey(false);
      }
    } else {
      alert("API Key selection helper not available.");
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-950 text-indigo-400">
        <div className="animate-pulse flex flex-col items-center">
          <Key className="w-12 h-12 mb-4" />
          <p>Checking Access...</p>
        </div>
      </div>
    );
  }

  if (hasKey) {
    return null; // Should be handled by parent to show app
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-950 p-4">
      <div className="max-w-md w-full bg-slate-900 border border-slate-800 rounded-2xl p-8 shadow-2xl text-center">
        <div className="w-16 h-16 bg-indigo-500/10 rounded-full flex items-center justify-center mx-auto mb-6">
          <Key className="w-8 h-8 text-indigo-400" />
        </div>

        <h1 className="text-2xl font-bold text-white mb-2">需要 API 金鑰</h1>
        <p className="text-slate-400 mb-8">
          要使用「Level Up Life」的高級圖像生成功能 (Gemini 3 Pro Image)，您需要連接您自己的 Google Cloud 付費專案 API 金鑰。
        </p>

        <button
          onClick={handleSelectKey}
          className="w-full py-3 px-4 bg-indigo-600 hover:bg-indigo-500 text-white font-semibold rounded-lg transition-colors flex items-center justify-center gap-2 mb-4"
        >
          <Key className="w-5 h-5" />
          選擇 API 金鑰
        </button>

        <a 
          href="https://ai.google.dev/gemini-api/docs/billing" 
          target="_blank" 
          rel="noopener noreferrer"
          className="inline-flex items-center text-sm text-slate-500 hover:text-indigo-400 transition-colors"
        >
          關於計費說明 <ExternalLink className="w-3 h-3 ml-1" />
        </a>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { UserStats, STAT_LABELS } from '../types';
import { generateAvatarImage } from '../services/geminiService';
import { Wand2, Download, RefreshCw, AlertCircle } from 'lucide-react';

interface AvatarGeneratorProps {
  stats: UserStats;
}

const ASPECT_RATIOS = [
  { value: '1:1', label: '1:1 (正方形)' },
  { value: '2:3', label: '2:3 (肖像)' },
  { value: '3:2', label: '3:2 (風景)' },
  { value: '3:4', label: '3:4 (直式)' },
  { value: '4:3', label: '4:3 (橫式)' },
  { value: '9:16', label: '9:16 (手機桌布)' },
  { value: '16:9', label: '16:9 (電腦桌布)' },
  { value: '21:9', label: '21:9 (超寬螢幕)' },
];

const IMAGE_SIZES = [
  { value: '1K', label: '1K (標準)' },
  { value: '2K', label: '2K (高清)' },
  { value: '4K', label: '4K (超高清)' },
];

export const AvatarGenerator: React.FC<AvatarGeneratorProps> = ({ stats }) => {
  const [loading, setLoading] = useState(false);
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const [customPrompt, setCustomPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState('1:1');
  const [imageSize, setImageSize] = useState('1K');

  const handleGenerate = async () => {
    setLoading(true);
    setError(null);

    // Construct a prompt based on stats if custom prompt is empty, or combine them
    const statsDesc = Object.entries(stats.attributes)
      .map(([key, val]) => `${STAT_LABELS[key as keyof typeof STAT_LABELS]}: ${val}`)
      .join(', ');

    const basePrompt = customPrompt.trim() 
      ? customPrompt 
      : `一個史詩般的 RPG 角色肖像，風格是數位繪畫，高品質。角色等級 ${stats.level}。屬性特徵: ${statsDesc}。看起來強大且充滿細節。`;

    const finalPrompt = `Create an image of: ${basePrompt}`;

    try {
      const result = await generateAvatarImage({
        prompt: finalPrompt,
        aspectRatio,
        imageSize
      });
      setImageUrl(result);
    } catch (err) {
      setError("生成圖片失敗，請稍後再試。");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl">
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-purple-500/20 rounded-lg">
          <Wand2 className="w-6 h-6 text-purple-400" />
        </div>
        <h2 className="text-xl font-bold text-white">角色形象生成</h2>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Controls */}
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">
              外觀描述 (提示詞)
            </label>
            <textarea
              className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-sm text-slate-200 focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none resize-none h-24"
              placeholder="例如：一位穿著發光盔甲的賽博龐克騎士，手持藍色雷射劍..."
              value={customPrompt}
              onChange={(e) => setCustomPrompt(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-1">
                長寬比
              </label>
              <select
                value={aspectRatio}
                onChange={(e) => setAspectRatio(e.target.value)}
                className="w-full bg-slate-950 border border-slate-800 rounded-lg p-2.5 text-sm text-slate-200 outline-none focus:ring-2 focus:ring-purple-500"
              >
                {ASPECT_RATIOS.map((ratio) => (
                  <option key={ratio.value} value={ratio.value}>
                    {ratio.label}
                  </option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-400 mb-1">
                解析度
              </label>
              <select
                value={imageSize}
                onChange={(e) => setImageSize(e.target.value)}
                className="w-full bg-slate-950 border border-slate-800 rounded-lg p-2.5 text-sm text-slate-200 outline-none focus:ring-2 focus:ring-purple-500"
              >
                {IMAGE_SIZES.map((size) => (
                  <option key={size.value} value={size.value}>
                    {size.label}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <button
            onClick={handleGenerate}
            disabled={loading}
            className={`w-full py-3 px-4 rounded-lg font-bold flex items-center justify-center gap-2 transition-all ${
              loading
                ? 'bg-slate-800 text-slate-500 cursor-not-allowed'
                : 'bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-500 hover:to-indigo-500 text-white shadow-lg hover:shadow-purple-500/25'
            }`}
          >
            {loading ? (
              <>
                <RefreshCw className="w-5 h-5 animate-spin" />
                生成中 (Gemini Thinking)...
              </>
            ) : (
              <>
                <Wand2 className="w-5 h-5" />
                生成角色
              </>
            )}
          </button>

          {error && (
            <div className="flex items-center gap-2 text-red-400 text-sm bg-red-900/20 p-3 rounded-lg">
              <AlertCircle className="w-4 h-4" />
              {error}
            </div>
          )}
        </div>

        {/* Preview */}
        <div className="flex flex-col items-center justify-center bg-slate-950 rounded-xl border border-slate-800 min-h-[300px] relative overflow-hidden group">
          {imageUrl ? (
            <>
              <img 
                src={imageUrl} 
                alt="Generated Avatar" 
                className="w-full h-full object-contain max-h-[400px]"
              />
              <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                <a 
                  href={imageUrl} 
                  download="rpg-avatar.png"
                  className="bg-white text-slate-900 px-4 py-2 rounded-full font-bold flex items-center gap-2 hover:scale-105 transition-transform"
                >
                  <Download className="w-4 h-4" />
                  下載圖片
                </a>
              </div>
            </>
          ) : (
            <div className="text-center text-slate-500">
              <div className="w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center mx-auto mb-3 border border-slate-800">
                <Wand2 className="w-8 h-8 opacity-20" />
              </div>
              <p>預覽區域</p>
              <p className="text-xs mt-1">你的角色將會出現在這裡</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer,
  BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid
} from 'recharts';
import { Plus, Check, Trash2, Trophy, Zap, Brain, Activity, Smile, Sword } from 'lucide-react';
import { Habit, UserStats, StatType, STAT_LABELS } from './types';
import { AvatarGenerator } from './components/AvatarGenerator';
import { ApiKeySelector } from './components/ApiKeySelector';

// Initial state helpers
const getInitialStats = (): UserStats => ({
  level: 1,
  currentXp: 0,
  nextLevelXp: 100,
  attributes: {
    STR: 1,
    INT: 1,
    VIT: 1,
    DEX: 1,
    CHR: 1,
  },
});

const STAT_ICONS: Record<StatType, React.ReactNode> = {
  STR: <Sword className="w-4 h-4" />,
  INT: <Brain className="w-4 h-4" />,
  VIT: <Activity className="w-4 h-4" />,
  DEX: <Zap className="w-4 h-4" />,
  CHR: <Smile className="w-4 h-4" />,
};

const App: React.FC = () => {
  const [hasApiKey, setHasApiKey] = useState(false);
  const [habits, setHabits] = useState<Habit[]>([]);
  const [stats, setStats] = useState<UserStats>(getInitialStats());
  const [isModalOpen, setIsModalOpen] = useState(false);

  // New habit form state
  const [newHabitTitle, setNewHabitTitle] = useState('');
  const [newHabitStat, setNewHabitStat] = useState<StatType>('STR');

  // Load data from local storage on mount
  useEffect(() => {
    const savedHabits = localStorage.getItem('rpg_habits');
    const savedStats = localStorage.getItem('rpg_stats');
    if (savedHabits) setHabits(JSON.parse(savedHabits));
    if (savedStats) setStats(JSON.parse(savedStats));
  }, []);

  // Save data on change
  useEffect(() => {
    localStorage.setItem('rpg_habits', JSON.stringify(habits));
    localStorage.setItem('rpg_stats', JSON.stringify(stats));
  }, [habits, stats]);

  const addHabit = () => {
    if (!newHabitTitle.trim()) return;

    const newHabit: Habit = {
      id: crypto.randomUUID(),
      title: newHabitTitle,
      stat: newHabitStat,
      xpReward: 10,
      statReward: 1,
      completedDates: [],
      streak: 0,
    };

    setHabits([...habits, newHabit]);
    setNewHabitTitle('');
    setIsModalOpen(false);
  };

  const deleteHabit = (id: string) => {
    setHabits(habits.filter(h => h.id !== id));
  };

  const completeHabit = (id: string) => {
    const today = new Date().toISOString().split('T')[0];

    setHabits(habits.map(h => {
      if (h.id === id) {
        if (h.completedDates.includes(today)) return h; // Already done today

        const newCompletedDates = [...h.completedDates, today];
        // Simple streak logic
        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        const yesterdayStr = yesterday.toISOString().split('T')[0];
        const isConsecutive = h.completedDates.includes(yesterdayStr);

        return {
          ...h,
          completedDates: newCompletedDates,
          streak: isConsecutive ? h.streak + 1 : 1
        };
      }
      return h;
    }));

    // Update stats
    const habit = habits.find(h => h.id === id);
    if (habit && !habit.completedDates.includes(today)) {
      setStats(prev => {
        let newXp = prev.currentXp + habit.xpReward;
        let newLevel = prev.level;
        let nextXp = prev.nextLevelXp;
        const newAttributes = { ...prev.attributes };

        // Stat increase
        newAttributes[habit.stat] += habit.statReward;

        // Level up logic
        while (newXp >= nextXp) {
          newXp -= nextXp;
          newLevel += 1;
          nextXp = Math.floor(nextXp * 1.2); // Harder to level up
        }

        return {
          level: newLevel,
          currentXp: newXp,
          nextLevelXp: nextXp,
          attributes: newAttributes
        };
      });
    }
  };

  // Data for Radar Chart
  const radarData = Object.entries(stats.attributes).map(([key, value]) => ({
    subject: key,
    A: value,
    fullMark: Math.max(...Object.values(stats.attributes)) * 1.2
  }));

  // Data for Weekly Progress Chart
  const getWeeklyData = () => {
    const days = ['週日', '週一', '週二', '週三', '週四', '週五', '週六'];
    const today = new Date();
    const data = [];

    for (let i = 6; i >= 0; i--) {
      const d = new Date(today);
      d.setDate(today.getDate() - i);
      const dateStr = d.toISOString().split('T')[0];
      const count = habits.reduce((acc, h) => 
        acc + (h.completedDates.includes(dateStr) ? 1 : 0), 0
      );
      data.push({ name: days[d.getDay()], count });
    }
    return data;
  };

  if (!hasApiKey) {
    return <ApiKeySelector onKeySelected={() => setHasApiKey(true)} />;
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans pb-20">
      {/* Header / Navbar */}
      <header className="bg-slate-900 border-b border-slate-800 sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded flex items-center justify-center">
              <Trophy className="w-5 h-5 text-white" />
            </div>
            <span className="font-bold text-lg tracking-wide">Level Up Life</span>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <div className="text-xs text-slate-400">LV. {stats.level}</div>
              <div className="w-32 h-2 bg-slate-800 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-indigo-500 to-purple-500 transition-all duration-500"
                  style={{ width: `${(stats.currentXp / stats.nextLevelXp) * 100}%` }}
                />
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Column: Stats & Avatar */}
        <div className="lg:col-span-1 space-y-6">
          {/* Stats Card */}
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
              <Activity className="w-5 h-5 text-indigo-400" />
              能力值 (Stats)
            </h2>

            <div className="h-[250px] w-full flex items-center justify-center -ml-4">
              <ResponsiveContainer width="100%" height="100%">
                <RadarChart cx="50%" cy="50%" outerRadius="70%" data={radarData}>
                  <PolarGrid stroke="#334155" />
                  <PolarAngleAxis dataKey="subject" tick={{ fill: '#94a3b8', fontSize: 12 }} />
                  <PolarRadiusAxis angle={30} domain={[0, 'auto']} tick={false} axisLine={false} />
                  <Radar
                    name="Stats"
                    dataKey="A"
                    stroke="#818cf8"
                    fill="#6366f1"
                    fillOpacity={0.4}
                  />
                  <Tooltip 
                    contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                    itemStyle={{ color: '#818cf8' }}
                  />
                </RadarChart>
              </ResponsiveContainer>
            </div>

            <div className="grid grid-cols-2 gap-3 mt-2">
              {(Object.keys(stats.attributes) as StatType[]).map(key => (
                <div key={key} className="bg-slate-950 p-2 rounded border border-slate-800 flex justify-between items-center">
                  <span className="text-xs text-slate-400 flex items-center gap-1">
                    {STAT_ICONS[key]} {key}
                  </span>
                  <span className="font-mono font-bold text-indigo-400">{stats.attributes[key]}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Avatar Generator */}
          <AvatarGenerator stats={stats} />
        </div>

        {/* Right Column: Habits & Progress */}
        <div className="lg:col-span-2 space-y-8">

          {/* Progress Chart */}
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl">
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
              <Activity className="w-5 h-5 text-emerald-400" />
              本週活動紀錄
            </h2>
            <div className="h-[200px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={getWeeklyData()}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                  <XAxis dataKey="name" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
                  <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} allowDecimals={false} />
                  <Tooltip 
                    cursor={{ fill: '#1e293b' }}
                    contentStyle={{ backgroundColor: '#0f172a', borderColor: '#334155', color: '#f1f5f9' }}
                  />
                  <Bar dataKey="count" fill="#10b981" radius={[4, 4, 0, 0]} barSize={30} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* Habit List */}
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold flex items-center gap-2">
                <Zap className="w-5 h-5 text-yellow-400" />
                每日任務 (Habits)
              </h2>
              <button 
                onClick={() => setIsModalOpen(true)}
                className="bg-indigo-600 hover:bg-indigo-500 text-white px-3 py-1.5 rounded-lg text-sm font-medium transition-colors flex items-center gap-1"
              >
                <Plus className="w-4 h-4" /> 新增習慣
              </button>
