export type StatType = 'STR' | 'INT' | 'VIT' | 'DEX' | 'CHR';
export type HabitType = 'good' | 'bad';

export const STAT_LABELS: Record<StatType, string> = {
  STR: '力量 (Strength)',
  INT: '智力 (Intelligence)',
  VIT: '體力 (Vitality)',
  DEX: '敏捷 (Dexterity)',
  CHR: '魅力 (Charisma)',
};

export interface Habit {
  id: string;
  title: string;
  description?: string;
  type: HabitType;
  stat: StatType;
  xpReward: number;
  statReward: number;
  completedDates: string[]; // ISO date strings YYYY-MM-DD
  streak: number;
  createdAt: string;
}

export interface UserStats {
  level: number;
  currentXp: number;
  nextLevelXp: number;
  attributes: Record<StatType, number>;
}

export interface User {
  username: string;
  isLoggedIn: boolean;
}

export interface AppData {
  habits: Habit[];
  stats: UserStats;
}

import React from 'react';
import { eachDayOfInterval, subDays, format, isSameDay, getDay } from 'date-fns';
import { twMerge } from 'tailwind-merge';
import { Habit } from '../types';

interface ContributionGraphProps {
  habits: Habit[];
  selectedDate: Date;
  onDateSelect: (date: Date) => void;
  theme?: 'emerald' | 'rose';
}

export const ContributionGraph: React.FC<ContributionGraphProps> = ({ 
  habits, 
  selectedDate,
  onDateSelect,
  theme = 'emerald'
}) => {
  const today = new Date();
  // Show last 365 days approx (52 weeks)
  const startDate = subDays(today, 364); 
  const days = eachDayOfInterval({ start: startDate, end: today });

  // Calculate intensity map
  const intensityMap = new Map<string, number>();

  days.forEach(day => {
    const dateStr = format(day, 'yyyy-MM-dd');
    let completedCount = 0;
    habits.forEach(habit => {
      if (habit.completedDates.includes(dateStr)) {
        completedCount++;
      }
    });
    intensityMap.set(dateStr, completedCount);
  });

  // Helper for color class based on theme
  const getColorClass = (count: number) => {
    if (count === 0) return 'bg-slate-800/50 hover:bg-slate-700';

    if (theme === 'rose') {
      if (count === 1) return 'bg-rose-900 hover:bg-rose-800';
      if (count === 2) return 'bg-rose-700 hover:bg-rose-600';
      if (count === 3) return 'bg-rose-500 hover:bg-rose-400';
      return 'bg-rose-400 hover:bg-rose-300 shadow-[0_0_10px_rgba(251,113,133,0.3)]';
    }

    // Default Emerald
    if (count === 1) return 'bg-emerald-900 hover:bg-emerald-800';
    if (count === 2) return 'bg-emerald-700 hover:bg-emerald-600';
    if (count === 3) return 'bg-emerald-500 hover:bg-emerald-400';
    return 'bg-emerald-400 hover:bg-emerald-300 shadow-[0_0_10px_rgba(52,211,153,0.3)]';
  };

  // Group by weeks for the grid
  const weeks: Date[][] = [];
  let currentWeek: Date[] = [];

  days.forEach((day) => {
    if (getDay(day) === 0 && currentWeek.length > 0) {
      weeks.push(currentWeek);
      currentWeek = [];
    }
    currentWeek.push(day);
  });
  if (currentWeek.length > 0) weeks.push(currentWeek);

  return (
    <div className="w-full overflow-x-auto pb-2">
      <div className="flex gap-1 min-w-max">
        {weeks.map((week, weekIndex) => (
          <div key={weekIndex} className="flex flex-col gap-1">
            {week.map((day) => {
              const dateStr = format(day, 'yyyy-MM-dd');
              const count = intensityMap.get(dateStr) || 0;
              const isSelected = isSameDay(day, selectedDate);
              const isToday = isSameDay(day, today);

              return (
                <div
                  key={dateStr}
                  onClick={() => onDateSelect(day)}
                  title={`${dateStr}: ${count} tasks`}
                  className={twMerge(
                    "w-3 h-3 rounded-sm cursor-pointer transition-all duration-200 border border-transparent",
                    getColorClass(count),
                    isSelected && "ring-2 ring-white border-transparent z-10 scale-125",
                    isToday && !isSelected && "border-indigo-500/50"
                  )}
                />
              );
            })}
          </div>
        ))}
      </div>
      <div className="flex justify-end items-center gap-2 mt-2 text-xs text-slate-500">
        <span>Less</span>
        <div className={`w-3 h-3 bg-slate-800 rounded-sm`}></div>
        <div className={`w-3 h-3 rounded-sm ${theme === 'rose' ? 'bg-rose-900' : 'bg-emerald-900'}`}></div>
        <div className={`w-3 h-3 rounded-sm ${theme === 'rose' ? 'bg-rose-700' : 'bg-emerald-700'}`}></div>
        <div className={`w-3 h-3 rounded-sm ${theme === 'rose' ? 'bg-rose-500' : 'bg-emerald-500'}`}></div>
        <div className={`w-3 h-3 rounded-sm ${theme === 'rose' ? 'bg-rose-400' : 'bg-emerald-400'}`}></div>
        <span>More</span>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer,
  Tooltip
} from 'recharts';
import { Plus, Check, Trash2, Trophy, Zap, Brain, Activity, Smile, Sword, Calendar, LogOut, Skull, AlertCircle } from 'lucide-react';
import { format, isSameDay } from 'date-fns';
import { Habit, UserStats, StatType, STAT_LABELS, User, HabitType } from './types';
import { Login } from './components/Login';
import { ContributionGraph } from './components/ContributionGraph';
import { MockDB } from './services/db';

const STAT_ICONS: Record<StatType, React.ReactNode> = {
  STR: <Sword className="w-4 h-4" />,
  INT: <Brain className="w-4 h-4" />,
  VIT: <Activity className="w-4 h-4" />,
  DEX: <Zap className="w-4 h-4" />,
  CHR: <Smile className="w-4 h-4" />,
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [stats, setStats] = useState<UserStats>({
    level: 1, currentXp: 0, nextLevelXp: 100,
    attributes: { STR: 1, INT: 1, VIT: 1, DEX: 1, CHR: 1 }
  });

  // UI State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [activeTab, setActiveTab] = useState<HabitType>('good');

  // Form State
  const [newHabitTitle, setNewHabitTitle] = useState('');
  const [newHabitStat, setNewHabitStat] = useState<StatType>('STR');
  const [newHabitType, setNewHabitType] = useState<HabitType>('good');

  // Check for existing session
  useEffect(() => {
    const savedUser = localStorage.getItem('rpg_current_user');
    if (savedUser) {
      handleLogin(savedUser);
    } else {
      setLoading(false);
    }
  }, []);

  const handleLogin = async (username: string) => {
    setLoading(true);
    const data = await MockDB.login(username);
    // Ensure existing habits have a type (migration)
    const migratedHabits = data.habits.map(h => ({ ...h, type: h.type || 'good' }));
    setHabits(migratedHabits);
    setStats(data.stats);
    setUser({ username, isLoggedIn: true });
    localStorage.setItem('rpg_current_user', username);
    setLoading(false);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('rpg_current_user');
    setHabits([]);
  };

  // Auto-save whenever data changes
  useEffect(() => {
    if (user) {
      MockDB.save(user.username, { habits, stats });
    }
  }, [habits, stats, user]);

  const addHabit = () => {
    if (!newHabitTitle.trim()) return;

    const newHabit: Habit = {
      id: crypto.randomUUID(),
      title: newHabitTitle,
      type: newHabitType,
      stat: newHabitStat,
      xpReward: 10,
      statReward: 1,
      completedDates: [],
      streak: 0,
      createdAt: new Date().toISOString()
    };

    setHabits([...habits, newHabit]);
    setNewHabitTitle('');
    setIsModalOpen(false);
  };

  const deleteHabit = (id: string) => {
    if (confirm('確定要刪除這個任務嗎？所有的歷史記錄將會被保留，但任務將不再顯示。')) {
       setHabits(habits.filter(h => h.id !== id));
    }
  };

  const toggleHabitCompletion = (id: string) => {
    const dateStr = format(selectedDate, 'yyyy-MM-dd');

    setHabits(prevHabits => {
      const habit = prevHabits.find(h => h.id === id);
      if (!habit) return prevHabits;

      const isCompleted = habit.completedDates.includes(dateStr);
      let newCompletedDates: string[];
      let xpChange = 0;
      let statChange = 0;

      // Logic Table:
      // Good Habit: Do (+) => Gain Rewards | Undo (-) => Lose Rewards
      // Bad Habit:  Do (+) => Lose Rewards | Undo (-) => Gain Rewards (Restore)

      const multiplier = habit.type === 'good' ? 1 : -1;

      if (isCompleted) {
        // Undoing an action
        newCompletedDates = habit.completedDates.filter(d => d !== dateStr);
        xpChange = -1 * habit.xpReward * multiplier;
        statChange = -1 * habit.statReward * multiplier;
      } else {
        // Performing an action
        newCompletedDates = [...habit.completedDates, dateStr];
        xpChange = habit.xpReward * multiplier;
        statChange = habit.statReward * multiplier;
      }

      // Update Stats
      setStats(prevStats => {
        let newXp = Math.max(0, prevStats.currentXp + xpChange);
        let newAttributes = { ...prevStats.attributes };
        newAttributes[habit.stat] = Math.max(1, newAttributes[habit.stat] + statChange);

        let newLevel = prevStats.level;
        let nextXp = prevStats.nextLevelXp;

        // Level Up Logic (Only handle leveling up, not down to avoid abuse/complexity)
        while (newXp >= nextXp) {
          newXp -= nextXp;
          newLevel += 1;
          nextXp = Math.floor(nextXp * 1.2);
        }

        // Simplistic Level Down protection: 
        // We just don't lower the level even if XP goes negative relative to previous level cap in a full implementation,
        // but here we are clamped at 0 current XP.

        return {
          ...prevStats,
          level: newLevel,
          currentXp: newXp,
          nextLevelXp: nextXp,
          attributes: newAttributes
        };
      });

      return prevHabits.map(h => 
        h.id === id 
          ? { ...h, completedDates: newCompletedDates } 
          : h
      );
    });
  };

  const openAddModal = (type: HabitType) => {
    setNewHabitType(type);
    setIsModalOpen(true);
  };

  if (loading) {
    return <div className="min-h-screen bg-slate-950 flex items-center justify-center text-slate-500">Loading...</div>;
  }

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  const radarData = Object.entries(stats.attributes).map(([key, value]) => ({
    subject: key,
    A: value,
    fullMark: Math.max(...Object.values(stats.attributes)) * 1.2
  }));

  const isSelectedToday = isSameDay(selectedDate, new Date());

  // Filter habits based on active tab
  const displayHabits = habits.filter(h => h.type === activeTab);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans pb-20">
      {/* Header */}
      <header className="bg-slate-900 border-b border-slate-800 sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <Trophy className="w-5 h-5 text-white" />
            </div>
            <span className="font-bold text-lg tracking-wide hidden sm:inline">Level Up Life</span>
          </div>

          <div className="flex items-center gap-6">
            <div className="flex flex-col items-end min-w-[120px]">
              <div className="flex justify-between w-full text-xs mb-1">
                <span className="text-indigo-400 font-bold">LV. {stats.level}</span>
                <span className="text-slate-500">{stats.currentXp} / {stats.nextLevelXp} XP</span>
              </div>
              <div className="w-32 sm:w-48 h-2 bg-slate-800 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-indigo-500 to-purple-500 transition-all duration-500"
                  style={{ width: `${Math.min(100, (stats.currentXp / stats.nextLevelXp) * 100)}%` }}
                />
              </div>
            </div>

            <button 
              onClick={handleLogout}
              className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors"
              title="Logout"
            >
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Stats (4 cols) */}
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
              <Activity className="w-5 h-5 text-indigo-400" />
              屬性面板
            </h2>

            <div className="h-[250px] w-full flex items-center justify-center -ml-4">
              <ResponsiveContainer width="100%" height="100%">
                <RadarChart cx="50%" cy="50%" outerRadius="70%" data={radarData}>
                  <PolarGrid stroke="#334155" />
                  <PolarAngleAxis dataKey="subject" tick={{ fill: '#94a3b8', fontSize: 12, fontWeight: 'bold' }} />
                  <PolarRadiusAxis angle={30} domain={[0, 'auto']} tick={false} axisLine={false} />
                  <Radar
                    name="Stats"
                    dataKey="A"
                    stroke="#818cf8"
                    fill="#6366f1"
                    fillOpacity={0.4}
                  />
                  <Tooltip 
                    contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                    itemStyle={{ color: '#818cf8' }}
                  />
                </RadarChart>
              </ResponsiveContainer>
            </div>

            <div className="grid grid-cols-2 gap-3 mt-4">
              {(Object.keys(stats.attributes) as StatType[]).map(key => (
                <div key={key} className="bg-slate-950 p-2.5 rounded-lg border border-slate-800 flex justify-between items-center group hover:border-indigo-500/50 transition-colors">
                  <span className="text-xs text-slate-400 flex items-center gap-1.5 group-hover:text-slate-200">
                    {STAT_ICONS[key]} {key}
                  </span>
                  <span className="font-mono font-bold text-indigo-400 group-hover:text-indigo-300">{stats.attributes[key]}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Right Column: Dashboard & Habits (8 cols) */}
        <div className="lg:col-span-8 space-y-6">

          {/* Tabs for Good/Bad Habits */}
          <div className="flex gap-2 p-1 bg-slate-900 rounded-xl border border-slate-800 w-fit">
            <button
              onClick={() => setActiveTab('good')}
              className={`px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 transition-all ${
                activeTab === 'good' 
                  ? 'bg-emerald-600 text-white shadow-lg' 
                  : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
            >
              <Zap className="w-4 h-4" /> 好習慣 (Good)
            </button>
            <button
              onClick={() => setActiveTab('bad')}
              className={`px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 transition-all ${
                activeTab === 'bad' 
                  ? 'bg-rose-600 text-white shadow-lg' 
                  : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
            >
              <Skull className="w-4 h-4" /> 壞習慣 (Bad)
            </button>
          </div>

          {/* Contribution Graph */}
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl overflow-hidden">
            <h2 className={`text-xl font-bold mb-4 flex items-center gap-2 ${activeTab === 'bad' ? 'text-rose-400' : 'text-emerald-400'}`}>
              <Calendar className="w-5 h-5" />
              {activeTab === 'good' ? '修煉歷程' : '破戒記錄'}
            </h2>
            <ContributionGraph 
              habits={habits.filter(h => h.type === activeTab)}
              selectedDate={selectedDate}
              onDateSelect={setSelectedDate}
              theme={activeTab === 'bad' ? 'rose' : 'emerald'}
            />
          </div>

          {/* Habit List for Selected Date */}
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
              <div className="flex items-center gap-3">
                <div className={`p-2 rounded-lg ${isSelectedToday ? (activeTab === 'bad' ? 'bg-rose-500/20' : 'bg-emerald-500/20') : 'bg-slate-800'}`}>
                  {activeTab === 'good' ? (
                    <Zap className={`w-5 h-5 ${isSelectedToday ? 'text-emerald-400' : 'text-slate-400'}`} />
                  ) : (
                    <Skull className={`w-5 h-5 ${isSelectedToday ? 'text-rose-400' : 'text-slate-400'}`} />
                  )}
                </div>
                <div>
                  <h2 className="text-xl font-bold text-white">
                    {isSelectedToday ? '今日項目' : format(selectedDate, 'yyyy-MM-dd') + ' 的項目'}
                  </h2>
                  <p className="text-xs text-slate-500 mt-1">
                    {activeTab === 'good' ? '完成習慣獲得獎勵' : '記錄壞習慣將受到懲罰'}
                  </p>
                </div>
              </div>

              <button 
                onClick={() => openAddModal(activeTab)}
                className={`w-full sm:w-auto px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center justify-center gap-2 shadow-lg ${
                  activeTab === 'good' 
                    ? 'bg-emerald-600 hover:bg-emerald-500 text-white shadow-emerald-500/20' 
                    : 'bg-rose-600 hover:bg-rose-500 text-white shadow-rose-500/20'
                }`}
              >
                <Plus className="w-4 h-4" /> 新增{activeTab === 'good' ? '好習慣' : '壞習慣'}
              </button>
            </div>

            <div className="space-y-3">
              {displayHabits.length === 0 && (
                <div className="text-center py-12 text-slate-500 border-2 border-dashed border-slate-800 rounded-xl bg-slate-950/50">
                  <p>這裡還沒有項目，去新增一個吧！</p>
                </div>
              )}

              {displayHabits.map(habit => {
                const dateStr = format(selectedDate, 'yyyy-MM-dd');
                const isCompleted = habit.completedDates.includes(dateStr);
                const isBad = habit.type === 'bad';

                return (
                  <div 
                    key={habit.id} 
                    className={`group relative flex items-center justify-between p-4 rounded-xl border transition-all duration-300 ${
                      isCompleted 
                        ? (isBad ? 'bg-rose-950/20 border-rose-900/50' : 'bg-emerald-950/20 border-emerald-900/50')
                        : 'bg-slate-950 border-slate-800 hover:border-slate-700'
                    }`}
                  >
                    <div className="flex items-center gap-4 w-full">
                      <button
                        onClick={() => toggleHabitCompletion(habit.id)}
                        className={`w-12 h-12 flex-shrink-0 rounded-xl flex items-center justify-center transition-all duration-300 ${
                          isCompleted
                            ? (isBad 
                                ? 'bg-rose-500 text-white shadow-[0_0_15px_rgba(244,63,94,0.4)] scale-105' 
                                : 'bg-emerald-500 text-white shadow-[0_0_15px_rgba(16,185,129,0.4)] scale-105'
                              )
                            : 'bg-slate-800 text-slate-600 hover:bg-slate-700 hover:text-white'
                        }`}
                        title={isBad ? (isCompleted ? "撤銷記錄 (恢復能力)" : "記錄發生 (扣除能力)") : (isCompleted ? "撤銷完成 (扣除獎勵)" : "完成 (獲得獎勵)")}
                      >
                        {isBad ? (
                          <AlertCircle className={`w-6 h-6 transition-transform ${isCompleted ? 'scale-110' : ''}`} />
                        ) : (
                          <Check className={`w-6 h-6 transition-transform ${isCompleted ? 'scale-110' : ''}`} />
                        )}
                      </button>

                      <div className="flex-1 min-w-0">
                        <h3 className={`font-semibold text-lg truncate ${isCompleted ? 'text-slate-400' : 'text-slate-100'}`}>
                          {habit.title}
                        </h3>
                        <div className="flex flex-wrap items-center gap-2 text-xs text-slate-400 mt-1">
                          <span className="flex items-center gap-1 px-1.5 py-0.5 bg-slate-900 rounded border border-slate-800">
                            {STAT_ICONS[habit.stat]} {habit.stat} {isBad ? '-' : '+'}{habit.statReward}
                          </span>
                          <span className="flex items-center gap-1 px-1.5 py-0.5 bg-slate-900 rounded border border-slate-800">
                            XP {isBad ? '-' : '+'}{habit.xpReward}
                          </span>
                        </div>
                      </div>
                    </div>

                    <button 
                      onClick={() => deleteHabit(habit.id)}
                      className="ml-2 opacity-0 group-hover:opacity-100 p-2 text-slate-600 hover:text-red-400 hover:bg-red-950/30 rounded-lg transition-all"
                      title="Delete"
                    >
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </main>

      {/* Add Habit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-md p-6 shadow-2xl transform transition-all scale-100 animate-in fade-in zoom-in duration-200">
            <h3 className="text-xl font-bold mb-4 text-white">新增{newHabitType === 'good' ? '好習慣' : '壞習慣'}</h3>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">名稱</label>
                <input
                  type="text"
                  value={newHabitTitle}
                  onChange={(e) => setNewHabitTitle(e.target.value)}
                  placeholder={newHabitType === 'good' ? "例如：閱讀 30 分鐘" : "例如：吃垃圾食物"}
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  autoFocus
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">
                  {newHabitType === 'good' ? '提升能力' : '扣除能力'}
                </label>
                <div className="grid grid-cols-2 gap-2">
                  {Object.entries(STAT_LABELS).map(([key, label]) => (
                    <button
                      key={key}
                      onClick={() => setNewHabitStat(key as StatType)}
                      className={`p-2 text-sm rounded-lg border flex items-center gap-2 transition-all ${
                        newHabitStat === key 
                          ? (newHabitType === 'good' 
                              ? 'bg-emerald-600 border-emerald-500 text-white' 
                              : 'bg-rose-600 border-rose-500 text-white')
                          : 'bg-slate-950 border-slate-700 text-slate-400 hover:border-slate-600 hover:bg-slate-900'
                      }`}
                    >
                      {STAT_ICONS[key as StatType]}
                      {key}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="flex gap-3 mt-8">
              <button
                onClick={() => setIsModalOpen(false)}
                className="flex-1 py-2.5 rounded-lg border border-slate-700 text-slate-300 hover:bg-slate-800 transition-colors"
              >
                取消
              </button>
              <button
                onClick={addHabit}
                className={`flex-1 py-2.5 rounded-lg text-white font-medium transition-colors shadow-lg ${
                   newHabitType === 'good'
                    ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-500/20'
                    : 'bg-rose-600 hover:bg-rose-500 shadow-rose-500/20'
                }`}
              >
                確認新增
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

