            ) : (
              <>
                <Wand2 className="w-5 h-5" />
                Generate
              </>
            )}
          </button>

          {error && (
            <div className="flex items-center gap-2 text-red-400 text-sm bg-red-900/20 p-3 rounded-lg">
              <AlertCircle className="w-4 h-4" />
              {error}
            </div>
          )}
        </div>

        {/* Preview */}
        <div className="flex flex-col items-center justify-center bg-slate-950 rounded-xl border border-slate-800 min-h-[300px] relative overflow-hidden group">
          {imageUrl ? (
            <>
              <img 
                src={imageUrl} 
                alt="Generated Avatar" 
                className="w-full h-full object-contain max-h-[400px]"
              />
              <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                <a 
                  href={imageUrl} 
                  download="rpg-avatar.png"
                  className="bg-white text-slate-900 px-4 py-2 rounded-full font-bold flex items-center gap-2 hover:scale-105 transition-transform"
                >
                  <Download className="w-4 h-4" />
                  Download
                </a>
              </div>
            </>
          ) : (
            <div className="text-center text-slate-500">
              <div className="w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center mx-auto mb-3 border border-slate-800">
                <Wand2 className="w-8 h-8 opacity-20" />
              </div>
              <p>Preview Area</p>
              <p className="text-xs mt-1">Your avatar will appear here</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer,
  Tooltip
} from 'recharts';
import { Plus, Check, Trash2, Trophy, Zap, Brain, Activity, Smile, Sword, Calendar, LogOut, Skull, AlertCircle, Heart, Send } from 'lucide-react';
import { format, isSameDay } from 'date-fns';
import { Habit, UserStats, StatType, STAT_LABELS, User, HabitType, GratitudeEntry } from './types';
import { Login } from './components/Login';
import { ContributionGraph } from './components/ContributionGraph';
import { MockDB } from './services/db';

const STAT_ICONS: Record<StatType, React.ReactNode> = {
  BODY: <Activity className="w-4 h-4" />,
  MIND: <Brain className="w-4 h-4" />,
  SOUL: <Heart className="w-4 h-4" />,
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [gratitudeLogs, setGratitudeLogs] = useState<GratitudeEntry[]>([]);
  const [stats, setStats] = useState<UserStats>({
    level: 1, currentXp: 0, nextLevelXp: 100,
    attributes: { BODY: 1, MIND: 1, SOUL: 1 }
  });

  // UI State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());

  // Dashboard view state: 'positive' or 'negative'
  const [dashboardView, setDashboardView] = useState<'positive' | 'negative'>('positive');

  // Form State
  const [newHabitTitle, setNewHabitTitle] = useState('');
  const [newHabitStat, setNewHabitStat] = useState<StatType>('BODY');
  const [newHabitType, setNewHabitType] = useState<HabitType>('good');
  const [gratitudeInput, setGratitudeInput] = useState('');

  // Check for existing session
  useEffect(() => {
    const savedUser = localStorage.getItem('rpg_current_user');
    if (savedUser) {
      handleLogin(savedUser);
    } else {
      setLoading(false);
    }
  }, []);

  const handleLogin = async (username: string) => {
    setLoading(true);
    const data = await MockDB.login(username);
    const migratedHabits = data.habits.map(h => ({ ...h, type: h.type || 'good' }));
    setHabits(migratedHabits);
    setGratitudeLogs(data.gratitudeLogs || []);
    setStats(data.stats);
    setUser({ username, isLoggedIn: true });
    localStorage.setItem('rpg_current_user', username);
    setLoading(false);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('rpg_current_user');
    setHabits([]);
    setGratitudeLogs([]);
  };

  // Auto-save whenever data changes
  useEffect(() => {
    if (user) {
      MockDB.save(user.username, { habits, gratitudeLogs, stats });
    }
  }, [habits, gratitudeLogs, stats, user]);

  const addHabit = () => {
    if (!newHabitTitle.trim()) return;

    const newHabit: Habit = {
      id: crypto.randomUUID(),
      title: newHabitTitle,
      type: newHabitType,
      stat: newHabitStat,
      xpReward: 10,
      statReward: 1,
      completedDates: [],
      streak: 0,
      createdAt: new Date().toISOString()
    };

    setHabits([...habits, newHabit]);
    setNewHabitTitle('');
    setIsModalOpen(false);
  };

  const deleteHabit = (id: string) => {
    if (confirm('Are you sure you want to delete this habit? History will be kept but it will disappear from the list.')) {
       setHabits(habits.filter(h => h.id !== id));
    }
  };

  const updateStats = (xpChange: number, stat: StatType, statChange: number) => {
    setStats(prevStats => {
      let newXp = Math.max(0, prevStats.currentXp + xpChange);
      let newAttributes = { ...prevStats.attributes };
      newAttributes[stat] = Math.max(1, newAttributes[stat] + statChange);

      let newLevel = prevStats.level;
      let nextXp = prevStats.nextLevelXp;

      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }

      return {
        ...prevStats,
        level: newLevel,
        currentXp: newXp,
        nextLevelXp: nextXp,
        attributes: newAttributes
      };
    });
  };

  const toggleHabitCompletion = (id: string) => {
    const dateStr = format(selectedDate, 'yyyy-MM-dd');

    setHabits(prevHabits => {
      const habit = prevHabits.find(h => h.id === id);
      if (!habit) return prevHabits;

      const isCompleted = habit.completedDates.includes(dateStr);
      let newCompletedDates: string[];
      let xpChange = 0;
      let statChange = 0;

      const multiplier = habit.type === 'good' ? 1 : -1;

      if (isCompleted) {
        // Undoing
        newCompletedDates = habit.completedDates.filter(d => d !== dateStr);
        xpChange = -1 * habit.xpReward * multiplier;
        statChange = -1 * habit.statReward * multiplier;
      } else {
        // Doing
        newCompletedDates = [...habit.completedDates, dateStr];
        xpChange = habit.xpReward * multiplier;
        statChange = habit.statReward * multiplier;
      }

      updateStats(xpChange, habit.stat, statChange);

      return prevHabits.map(h => 
        h.id === id 
          ? { ...h, completedDates: newCompletedDates } 
          : h
      );
    });
  };

  const addGratitude = () => {
    if (!gratitudeInput.trim()) return;
    const dateStr = format(selectedDate, 'yyyy-MM-dd');

    const newEntry: GratitudeEntry = {
      id: crypto.randomUUID(),
      date: dateStr,
      content: gratitudeInput,
      createdAt: new Date().toISOString()
    };

    setGratitudeLogs(prev => [newEntry, ...prev]);
    setGratitudeInput('');
    // Reward for gratitude: XP +5, Soul +1
    updateStats(5, 'SOUL', 1);
  };

  const deleteGratitude = (id: string) => {
    if (confirm('Delete this gratitude entry? (Rewards will be deducted)')) {
      setGratitudeLogs(prev => prev.filter(g => g.id !== id));
      updateStats(-5, 'SOUL', -1);
    }
  };

  const openAddModal = (type: HabitType) => {
    setNewHabitType(type);
    setIsModalOpen(true);
  };

  if (loading) {
    return <div className="min-h-screen bg-slate-950 flex items-center justify-center text-slate-500">Loading...</div>;
  }

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  const radarData = Object.entries(stats.attributes).map(([key, value]) => ({
    subject: STAT_LABELS[key as StatType],
    A: value,
    fullMark: Math.max(...Object.values(stats.attributes)) * 1.2
  }));

  const isSelectedToday = isSameDay(selectedDate, new Date());
  const dateStr = format(selectedDate, 'yyyy-MM-dd');

  const goodHabits = habits.filter(h => h.type === 'good');
  const badHabits = habits.filter(h => h.type === 'bad');
  const dailyGratitudes = gratitudeLogs.filter(g => g.date === dateStr);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans pb-20">
      {/* Header */}
      <header className="bg-slate-900 border-b border-slate-800 sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <Trophy className="w-5 h-5 text-white" />
            </div>
            <span className="font-bold text-lg tracking-wide hidden sm:inline">Level Up Life</span>
          </div>

          <div className="flex items-center gap-6">
            <div className="flex flex-col items-end min-w-[120px]">
              <div className="flex justify-between w-full text-xs mb-1">
                <span className="text-indigo-400 font-bold">LV. {stats.level}</span>
                <span className="text-slate-500">{stats.currentXp} / {stats.nextLevelXp} XP</span>
              </div>
              <div className="w-32 sm:w-48 h-2 bg-slate-800 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-indigo-500 to-purple-500 transition-all duration-500"
                  style={{ width: `${Math.min(100, (stats.currentXp / stats.nextLevelXp) * 100)}%` }}
                />
              </div>
            </div>

            <button 
              onClick={handleLogout}
              className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors"
              title="Logout"
            >
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Stats (4 cols) */}
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
            <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
              <Activity className="w-5 h-5 text-indigo-400" />
              Attributes
            </h2>

            <div className="h-[250px] w-full flex items-center justify-center -ml-4">
              <ResponsiveContainer width="100%" height="100%">
                <RadarChart cx="50%" cy="50%" outerRadius="70%" data={radarData}>
                  <PolarGrid stroke="#334155" />
                  <PolarAngleAxis dataKey="subject" tick={{ fill: '#94a3b8', fontSize: 14, fontWeight: 'bold' }} />
                  <PolarRadiusAxis angle={30} domain={[0, 'auto']} tick={false} axisLine={false} />
                  <Radar
                    name="Stats"
                    dataKey="A"
                    stroke="#818cf8"
                    fill="#6366f1"
                    fillOpacity={0.4}
                  />
                  <Tooltip 
                    contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                    itemStyle={{ color: '#818cf8' }}
                  />
                </RadarChart>
              </ResponsiveContainer>
            </div>

            <div className="grid grid-cols-1 gap-3 mt-4">
              {(Object.keys(stats.attributes) as StatType[]).map(key => (
                <div key={key} className="bg-slate-950 p-3 rounded-lg border border-slate-800 flex justify-between items-center group hover:border-indigo-500/50 transition-colors">
                  <span className="text-sm text-slate-400 flex items-center gap-2 group-hover:text-slate-200">
                    {STAT_ICONS[key]} {STAT_LABELS[key]}
                  </span>
                  <span className="font-mono font-bold text-lg text-indigo-400 group-hover:text-indigo-300">{stats.attributes[key]}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Right Column: Dashboard & Habits (8 cols) */}
        <div className="lg:col-span-8 space-y-8">

          {/* Dashboard */}
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl overflow-hidden">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xl font-bold flex items-center gap-2 text-white">
                <Calendar className="w-5 h-5" />
                Dashboard
              </h2>

              <div className="flex gap-2 p-1 bg-slate-950 rounded-lg border border-slate-800">
                <button
                  onClick={() => setDashboardView('positive')}
                  className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${
                    dashboardView === 'positive' 
                      ? 'bg-emerald-600 text-white shadow' 
                      : 'text-slate-500 hover:text-slate-300'
                  }`}
                >
                  Positive Log
                </button>
                <button
                  onClick={() => setDashboardView('negative')}
                  className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${
                    dashboardView === 'negative' 
                      ? 'bg-rose-600 text-white shadow' 
                      : 'text-slate-500 hover:text-slate-300'
                  }`}
                >
                  Bad Habits
                </button>
              </div>
            </div>

            {dashboardView === 'positive' ? (
              <ContributionGraph 
                title="Activity Log (Habits & Gratitude)"
                habits={goodHabits}
                gratitudeLogs={gratitudeLogs}
                selectedDate={selectedDate}
                onDateSelect={setSelectedDate}
                theme="emerald"
              />
            ) : (
              <ContributionGraph 
                title="Bad Habit Relapses"
                habits={badHabits}
                // No gratitude logs for bad habits
                selectedDate={selectedDate}
                onDateSelect={setSelectedDate}
                theme="rose"
              />
            )}
          </div>

          <div className="text-center text-2xl font-bold text-white mb-2 sticky top-16 z-20 bg-slate-950/80 backdrop-blur-sm py-2 border-b border-slate-800/50">
             {format(selectedDate, 'MMMM d, yyyy')}
          </div>

          {/* Gratitude Section */}
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl relative overflow-hidden group">
            <div className="absolute top-0 left-0 w-1 h-full bg-amber-500"></div>
            <h2 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
              <Heart className="w-5 h-5 text-amber-500" /> Gratitude Journal
            </h2>

            <div className="mb-4">
              {dailyGratitudes.map(entry => (
                <div key={entry.id} className="bg-amber-950/20 border border-amber-900/30 p-3 rounded-lg mb-2 flex justify-between items-start">
                  <p className="text-amber-100">{entry.content}</p>
                  <button onClick={() => deleteGratitude(entry.id)} className="text-slate-600 hover:text-amber-500 transition-colors p-1">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              ))}
              {dailyGratitudes.length === 0 && (
                <p className="text-slate-500 text-sm italic mb-4">No gratitude entries for this day yet...</p>
              )}
            </div>

            <div className="flex gap-2">
              <input 
                type="text" 
                value={gratitudeInput}
                onChange={(e) => setGratitudeInput(e.target.value)}
                placeholder="What are you grateful for today? (SOUL +1)"
                className="flex-1 bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-amber-500 outline-none"
                onKeyDown={(e) => e.key === 'Enter' && addGratitude()}
              />
              <button 
                onClick={addGratitude}
                className="bg-amber-600 hover:bg-amber-500 text-white px-4 py-2 rounded-lg transition-colors flex items-center"
              >
                <Send className="w-4 h-4" />
              </button>
            </div>
          </div>

          {/* Good Habits */}
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Zap className="w-5 h-5 text-emerald-400" /> Good Habits
              </h2>
              <button 
                onClick={() => openAddModal('good')}
                className="bg-emerald-600 hover:bg-emerald-500 text-white px-3 py-1.5 rounded-lg text-sm font-medium transition-colors flex items-center gap-1 shadow-lg shadow-emerald-500/20"
              >
                <Plus className="w-4 h-4" /> Add
              </button>
            </div>

            <div className="space-y-3">
              {goodHabits.length === 0 && <p className="text-slate-500 text-center py-4">No habits added yet.</p>}
              {goodHabits.map(habit => {
                const isCompleted = habit.completedDates.includes(dateStr);
                return (
                  <div key={habit.id} className={`flex items-center justify-between p-4 rounded-xl border transition-all ${
                    isCompleted ? 'bg-emerald-950/20 border-emerald-900/50' : 'bg-slate-950 border-slate-800'
                  }`}>
                    <div className="flex items-center gap-4 flex-1">
                      <button
                        onClick={() => toggleHabitCompletion(habit.id)}
                        className={`w-10 h-10 rounded-lg flex items-center justify-center transition-all ${
                          isCompleted ? 'bg-emerald-500 text-white' : 'bg-slate-800 text-slate-600 hover:bg-slate-700'
                        }`}
                      >
                        <Check className="w-5 h-5" />
                      </button>
                      <div>
                        <h3 className={`font-semibold ${isCompleted ? 'text-slate-400' : 'text-slate-100'}`}>{habit.title}</h3>
                        <div className="flex gap-2 text-xs text-slate-500">
                          <span>{habit.stat} +{habit.statReward}</span>
                          <span>XP +{habit.xpReward}</span>
                        </div>
                      </div>
                    </div>
                    <button onClick={() => deleteHabit(habit.id)} className="text-slate-600 hover:text-red-400 p-2">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Bad Habits */}
          <div className="bg-slate-900 rounded-2xl border border-rose-900/30 p-6 shadow-xl">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Skull className="w-5 h-5 text-rose-400" /> Bad Habits
              </h2>
              <button 
                onClick={() => openAddModal('bad')}
                className="bg-rose-600 hover:bg-rose-500 text-white px-3 py-1.5 rounded-lg text-sm font-medium transition-colors flex items-center gap-1 shadow-lg shadow-rose-500/20"
              >
                <Plus className="w-4 h-4" /> Add
              </button>
            </div>

            <div className="space-y-3">
              {badHabits.length === 0 && <p className="text-slate-500 text-center py-4">No bad habits tracked.</p>}
              {badHabits.map(habit => {
                const isCompleted = habit.completedDates.includes(dateStr);
                return (
                  <div key={habit.id} className={`flex items-center justify-between p-4 rounded-xl border transition-all ${
                    isCompleted ? 'bg-rose-950/20 border-rose-900/50' : 'bg-slate-950 border-slate-800'
                  }`}>
                    <div className="flex items-center gap-4 flex-1">
                      <button
                        onClick={() => toggleHabitCompletion(habit.id)}
                        className={`w-10 h-10 rounded-lg flex items-center justify-center transition-all ${
                          isCompleted ? 'bg-rose-500 text-white' : 'bg-slate-800 text-slate-600 hover:bg-slate-700'
                        }`}
                        title="Click to log relapse (Penalty)"
                      >
                        <AlertCircle className="w-5 h-5" />
                      </button>
                      <div>
                        <h3 className={`font-semibold ${isCompleted ? 'text-rose-300' : 'text-slate-100'}`}>{habit.title}</h3>
                        <div className="flex gap-2 text-xs text-slate-500">
                          <span>{habit.stat} -{habit.statReward}</span>
                          <span>XP -{habit.xpReward}</span>
                        </div>
                      </div>
                    </div>
                    <button onClick={() => deleteHabit(habit.id)} className="text-slate-600 hover:text-red-400 p-2">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </main>

      {/* Add Habit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-md p-6 shadow-2xl transform transition-all scale-100 animate-in fade-in zoom-in duration-200">
            <h3 className="text-xl font-bold mb-4 text-white">Add {newHabitType === 'good' ? 'Good Habit' : 'Bad Habit'}</h3>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">Title</label>
                <input
                  type="text"
                  value={newHabitTitle}
                  onChange={(e) => setNewHabitTitle(e.target.value)}
                  placeholder={newHabitType === 'good' ? "e.g. Meditate for 10 mins" : "e.g. Stay up late"}
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-slate-100 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  autoFocus
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-1">
                  {newHabitType === 'good' ? 'Stat Reward' : 'Stat Penalty'}
                </label>
                <div className="grid grid-cols-3 gap-2">
                  {Object.entries(STAT_LABELS).map(([key, label]) => (
                    <button
                      key={key}
                      onClick={() => setNewHabitStat(key as StatType)}
                      className={`p-2 text-sm rounded-lg border flex flex-col items-center gap-1 transition-all ${
                        newHabitStat === key 
                          ? (newHabitType === 'good' 
                              ? 'bg-emerald-600 border-emerald-500 text-white' 
                              : 'bg-rose-600 border-rose-500 text-white')
                          : 'bg-slate-950 border-slate-700 text-slate-400 hover:border-slate-600 hover:bg-slate-900'
                      }`}
                    >
                      {STAT_ICONS[key as StatType]}
                      <span className="text-xs">{label}</span>
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="flex gap-3 mt-8">
              <button
                onClick={() => setIsModalOpen(false)}
                className="flex-1 py-2.5 rounded-lg border border-slate-700 text-slate-300 hover:bg-slate-800 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={addHabit}
                className={`flex-1 py-2.5 rounded-lg text-white font-medium transition-colors shadow-lg ${
                   newHabitType === 'good'
                    ? 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-500/20'
                    : 'bg-rose-600 hover:bg-rose-500 shadow-rose-500/20'
                }`}
              >
                Confirm
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  eachDayOfInterval, 
  format, 
  isSameDay, 
  getDay, 
  endOfMonth, 
  endOfWeek, 
  addMonths, 
  isSameMonth
} from 'date-fns';
import { twMerge } from 'tailwind-merge';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { Habit, GratitudeEntry } from '../types';

interface ContributionGraphProps {
  habits: Habit[];
  gratitudeLogs?: GratitudeEntry[]; // Optional, as bad habits graph won't use it
  selectedDate: Date;
  onDateSelect: (date: Date) => void;
  theme?: 'emerald' | 'rose';
  title: string;
}

export const ContributionGraph: React.FC<ContributionGraphProps> = ({ 
  habits, 
  gratitudeLogs = [],
  selectedDate,
  onDateSelect,
  theme = 'emerald',
  title
}) => {
  const [viewDate, setViewDate] = useState(new Date());

  const handlePrevMonth = () => setViewDate(addMonths(viewDate, -1));
  const handleNextMonth = () => setViewDate(addMonths(viewDate, 1));

  // Calculate range for the view (Month view tailored to weeks)
  const monthStart = new Date(viewDate.getFullYear(), viewDate.getMonth(), 1);
  const monthEnd = endOfMonth(viewDate);

  // Custom startOfWeek logic since import was failing
  const calendarStart = new Date(monthStart);
  calendarStart.setDate(monthStart.getDate() - monthStart.getDay());

  const calendarEnd = endOfWeek(monthEnd);

  const days = eachDayOfInterval({ start: calendarStart, end: calendarEnd });

  // Calculate intensity map
  const intensityMap = new Map<string, number>();

  days.forEach(day => {
    const dateStr = format(day, 'yyyy-MM-dd');
    let score = 0;

    // Count habits matching the passed list
    habits.forEach(habit => {
      if (habit.completedDates.includes(dateStr)) {
        score++;
      }
    });

    // Count gratitude logs if provided (only for good habits context)
    const gratitudeCount = gratitudeLogs.filter(log => log.date === dateStr).length;
    score += gratitudeCount;

    intensityMap.set(dateStr, score);
  });

  const getColorClass = (count: number) => {
    if (count === 0) return 'bg-slate-800/50 hover:bg-slate-700';

    if (theme === 'rose') {
        if (count === 1) return 'bg-rose-900 hover:bg-rose-800';
        if (count === 2) return 'bg-rose-700 hover:bg-rose-600';
        if (count >= 3) return 'bg-rose-500 hover:bg-rose-400 shadow-[0_0_10px_rgba(244,63,94,0.4)]';
        return 'bg-rose-500';
    } else {
        if (count === 1) return 'bg-emerald-900 hover:bg-emerald-800';
        if (count === 2) return 'bg-emerald-700 hover:bg-emerald-600';
        if (count >= 3) return 'bg-emerald-500 hover:bg-emerald-400 shadow-[0_0_10px_rgba(16,185,129,0.4)]';
        return 'bg-emerald-500';
    }
  };

  // Group by weeks for vertical columns (standard contribution graph is Col=Week, Row=Day)
  // But user asked for "move left and right", and "dashboard". 
  // A standard Calendar view (Row=Week, Col=Day) might be more intuitive for "bigger cells", 
  // but let's stick to the visual style of "Contribution Graph" (7 rows) but paginated by month horizontally.

  const weeks: Date[][] = [];
  let currentWeek: Date[] = [];

  days.forEach((day) => {
    if (getDay(day) === 0 && currentWeek.length > 0) {
      weeks.push(currentWeek);
      currentWeek = [];
    }
    currentWeek.push(day);
  });
  if (currentWeek.length > 0) weeks.push(currentWeek);

  return (
    <div className="w-full">
      <div className="flex items-center justify-between mb-6">
        <h3 className={`font-bold text-lg ${theme === 'rose' ? 'text-rose-400' : 'text-emerald-400'}`}>
          {title}
        </h3>
        <div className="flex items-center gap-4 bg-slate-950 rounded-lg p-1 border border-slate-800">
          <button onClick={handlePrevMonth} className="p-1 hover:bg-slate-800 rounded text-slate-400 hover:text-white">
            <ChevronLeft className="w-5 h-5" />
          </button>
          <span className="text-sm font-bold min-w-[100px] text-center">
            {format(viewDate, 'MMMM yyyy')}
          </span>
          <button onClick={handleNextMonth} className="p-1 hover:bg-slate-800 rounded text-slate-400 hover:text-white">
            <ChevronRight className="w-5 h-5" />
          </button>
        </div>
      </div>

      <div className="w-full overflow-x-auto pb-4 custom-scrollbar">
        <div className="flex gap-2 min-w-max justify-center">
          {weeks.map((week, weekIndex) => (
            <div key={weekIndex} className="flex flex-col gap-2">
              {week.map((day) => {
                const dateStr = format(day, 'yyyy-MM-dd');
                const count = intensityMap.get(dateStr) || 0;
                const isSelected = isSameDay(day, selectedDate);
                const isToday = isSameDay(day, new Date());
                const inCurrentMonth = isSameMonth(day, viewDate);

                return (
                  <div
                    key={dateStr}
                    onClick={() => onDateSelect(day)}
                    title={`${dateStr}: ${count} entries`}
                    className={twMerge(
                      "w-8 h-8 rounded-md cursor-pointer transition-all duration-200 border border-transparent flex items-center justify-center relative",
                      getColorClass(count),
                      !inCurrentMonth && "opacity-30 grayscale",
                      isSelected && "ring-2 ring-white border-transparent z-10 scale-110 shadow-lg",
                      isToday && !isSelected && "border-indigo-500/50"
                    )}
                  >
                    {/* Optional: Show day number for better calendar feel since cells are big */}
                    <span className={`text-[10px] ${count > 0 ? 'text-white/90' : 'text-slate-600'}`}>
                      {format(day, 'd')}
                    </span>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>

      <div className="flex justify-center items-center gap-3 mt-4 text-xs text-slate-500">
        <span>Less</span>
        <div className="w-4 h-4 bg-slate-800 rounded"></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-900' : 'bg-emerald-900'}`}></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-700' : 'bg-emerald-700'}`}></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-500' : 'bg-emerald-500'}`}></div>
        <span>More</span>
      </div>
    </div>
  );
};

import React, { useLayoutEffect, useRef } from 'react';
import { 
  eachDayOfInterval, 
  format, 
  isSameDay, 
  getDay, 
  subDays,
  startOfWeek,
  endOfWeek
} from 'date-fns';
import { twMerge } from 'tailwind-merge';
import { Habit, GratitudeEntry } from '../types';

interface ContributionGraphProps {
  habits: Habit[];
  gratitudeLogs?: GratitudeEntry[]; 
  selectedDate: Date;
  onDateSelect: (date: Date) => void;
  theme?: 'emerald' | 'rose';
  title: string;
}

export const ContributionGraph: React.FC<ContributionGraphProps> = ({ 
  habits, 
  gratitudeLogs = [],
  selectedDate,
  onDateSelect,
  theme = 'emerald',
  title
}) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const today = new Date();

  // Show last 365 days for "infinite" feel scrolling
  const startDate = subDays(today, 365);

  // Align to weeks to ensure the grid looks square
  const calendarStart = startOfWeek(startDate);
  const calendarEnd = endOfWeek(today);

  const days = eachDayOfInterval({ start: calendarStart, end: calendarEnd });

  // Auto-scroll to the right (latest date) on mount
  useLayoutEffect(() => {
    if (scrollContainerRef.current) {
      scrollContainerRef.current.scrollLeft = scrollContainerRef.current.scrollWidth;
    }
  }, []);

  // Calculate intensity map
  const intensityMap = new Map<string, number>();

  days.forEach(day => {
    const dateStr = format(day, 'yyyy-MM-dd');
    let score = 0;

    // Count habits
    habits.forEach(habit => {
      if (habit.completedDates.includes(dateStr)) {
        score++;
      }
    });

    // Count gratitude
    const gratitudeCount = gratitudeLogs.filter(log => log.date === dateStr).length;
    score += gratitudeCount;

    intensityMap.set(dateStr, score);
  });

  const getColorClass = (count: number) => {
    if (count === 0) return 'bg-slate-800/50 hover:bg-slate-700';

    if (theme === 'rose') {
        if (count === 1) return 'bg-rose-900 hover:bg-rose-800';
        if (count === 2) return 'bg-rose-700 hover:bg-rose-600';
        if (count >= 3) return 'bg-rose-500 hover:bg-rose-400 shadow-[0_0_10px_rgba(244,63,94,0.4)]';
        return 'bg-rose-500';
    } else {
        if (count === 1) return 'bg-emerald-900 hover:bg-emerald-800';
        if (count === 2) return 'bg-emerald-700 hover:bg-emerald-600';
        if (count >= 3) return 'bg-emerald-500 hover:bg-emerald-400 shadow-[0_0_10px_rgba(16,185,129,0.4)]';
        return 'bg-emerald-500';
    }
  };

  // Group by weeks
  const weeks: Date[][] = [];
  let currentWeek: Date[] = [];

  days.forEach((day) => {
    if (getDay(day) === 0 && currentWeek.length > 0) {
      weeks.push(currentWeek);
      currentWeek = [];
    }
    currentWeek.push(day);
  });
  if (currentWeek.length > 0) weeks.push(currentWeek);

  return (
    <div className="w-full">
      <div className="flex items-center justify-between mb-4">
        <h3 className={`font-bold text-lg ${theme === 'rose' ? 'text-rose-400' : 'text-emerald-400'}`}>
          {title}
        </h3>
        <div className="text-xs text-slate-500">
          Scroll for history &rarr;
        </div>
      </div>

      {/* Horizontal Scroll Container */}
      <div 
        ref={scrollContainerRef}
        className="w-full overflow-x-auto pb-4 custom-scrollbar"
      >
        <div className="flex gap-2 min-w-max">
          {weeks.map((week, weekIndex) => (
            <div key={weekIndex} className="flex flex-col gap-2">
              {week.map((day) => {
                const dateStr = format(day, 'yyyy-MM-dd');
                const count = intensityMap.get(dateStr) || 0;
                const isSelected = isSameDay(day, selectedDate);
                const isToday = isSameDay(day, today);

                return (
                  <div
                    key={dateStr}
                    onClick={() => onDateSelect(day)}
                    title={`${dateStr}: ${count} entries`}
                    className={twMerge(
                      "w-6 h-6 rounded cursor-pointer transition-all duration-200 border border-transparent flex items-center justify-center relative",
                      getColorClass(count),
                      isSelected && "ring-2 ring-white border-transparent z-10 scale-125 shadow-lg",
                      isToday && !isSelected && "border-indigo-500/50"
                    )}
                  >
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>

      <div className="flex justify-end items-center gap-3 mt-2 text-xs text-slate-500">
        <span>Less</span>
        <div className="w-4 h-4 bg-slate-800 rounded"></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-900' : 'bg-emerald-900'}`}></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-700' : 'bg-emerald-700'}`}></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-500' : 'bg-emerald-500'}`}></div>
        <span>More</span>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer,
  Tooltip
} from 'recharts';
import { Plus, Check, Trash2, Trophy, Zap, Brain, Activity, Smile, Sword, Calendar, LogOut, Skull, AlertCircle, Heart, Send, Star } from 'lucide-react';
import { format, isSameDay } from 'date-fns';
import { Habit, UserStats, StatType, STAT_LABELS, User, HabitType, GratitudeEntry } from './types';
import { Login } from './components/Login';
import { ContributionGraph } from './components/ContributionGraph';
import { MockDB } from './services/db';
import { ApiKeySelector } from './components/ApiKeySelector';
import { AvatarGenerator } from './components/AvatarGenerator';

const STAT_ICONS: Record<StatType, React.ReactNode> = {
  BODY: <Activity className="w-4 h-4" />,
  MIND: <Brain className="w-4 h-4" />,
  SOUL: <Heart className="w-4 h-4" />,
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [gratitudeLogs, setGratitudeLogs] = useState<GratitudeEntry[]>([]);
  const [stats, setStats] = useState<UserStats>({
    level: 1, currentXp: 0, nextLevelXp: 100,
    attributes: { BODY: 1, MIND: 1, SOUL: 1 }
  });

  // UI State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [showAvatarGen, setShowAvatarGen] = useState(false);

  // Dashboard view state: 'positive' or 'negative'
  const [dashboardView, setDashboardView] = useState<'positive' | 'negative'>('positive');

  // Form State
  const [newHabitTitle, setNewHabitTitle] = useState('');
  const [newHabitStat, setNewHabitStat] = useState<StatType>('BODY');
  const [newHabitType, setNewHabitType] = useState<HabitType>('good');
  const [gratitudeInput, setGratitudeInput] = useState('');

  // Check for existing session
  useEffect(() => {
    const savedUser = localStorage.getItem('rpg_current_user');
    if (savedUser) {
      handleLogin(savedUser);
    } else {
      setLoading(false);
    }
  }, []);

  const handleLogin = async (username: string) => {
    setLoading(true);
    const data = await MockDB.login(username);
    const migratedHabits = data.habits.map(h => ({ ...h, type: h.type || 'good' }));
    setHabits(migratedHabits);
    setGratitudeLogs(data.gratitudeLogs || []);
    setStats(data.stats);
    setUser({ username, isLoggedIn: true });
    localStorage.setItem('rpg_current_user', username);
    setLoading(false);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('rpg_current_user');
    setHabits([]);
    setGratitudeLogs([]);
  };

  // Auto-save whenever data changes
  useEffect(() => {
    if (user) {
      MockDB.save(user.username, { habits, gratitudeLogs, stats });
    }
  }, [habits, gratitudeLogs, stats, user]);

  const addHabit = () => {
    if (!newHabitTitle.trim()) return;

    const newHabit: Habit = {
      id: crypto.randomUUID(),
      title: newHabitTitle,
      type: newHabitType,
      stat: newHabitStat,
      xpReward: 10,
      statReward: 1,
      completedDates: [],
      streak: 0,
      createdAt: new Date().toISOString()
    };

    setHabits([...habits, newHabit]);
    setNewHabitTitle('');
    setIsModalOpen(false);
  };

  const deleteHabit = (id: string) => {
    if (confirm('Are you sure you want to delete this habit? History will be kept but it will disappear from the list.')) {
       setHabits(habits.filter(h => h.id !== id));
    }
  };

  const updateStats = (xpChange: number, stat: StatType, statChange: number) => {
    setStats(prevStats => {
      let newXp = Math.max(0, prevStats.currentXp + xpChange);
      let newAttributes = { ...prevStats.attributes };
      newAttributes[stat] = Math.max(1, newAttributes[stat] + statChange);

      let newLevel = prevStats.level;
      let nextXp = prevStats.nextLevelXp;

      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }

      return {
        ...prevStats,
        level: newLevel,
        currentXp: newXp,
        nextLevelXp: nextXp,
        attributes: newAttributes
      };
    });
  };

  const toggleHabitCompletion = (id: string) => {
    const dateStr = format(selectedDate, 'yyyy-MM-dd');

    setHabits(prevHabits => {
      const habit = prevHabits.find(h => h.id === id);
      if (!habit) return prevHabits;

      const isCompleted = habit.completedDates.includes(dateStr);
      let newCompletedDates: string[];
      let xpChange = 0;
      let statChange = 0;

      const multiplier = habit.type === 'good' ? 1 : -1;

      if (isCompleted) {
        // Undoing
        newCompletedDates = habit.completedDates.filter(d => d !== dateStr);
        xpChange = -1 * habit.xpReward * multiplier;
        statChange = -1 * habit.statReward * multiplier;
      } else {
        // Doing
        newCompletedDates = [...habit.completedDates, dateStr];
        xpChange = habit.xpReward * multiplier;
        statChange = habit.statReward * multiplier;
      }

      updateStats(xpChange, habit.stat, statChange);

      return prevHabits.map(h => 
        h.id === id 
          ? { ...h, completedDates: newCompletedDates } 
          : h
      );
    });
  };

  const addGratitude = () => {
    if (!gratitudeInput.trim()) return;
    const dateStr = format(selectedDate, 'yyyy-MM-dd');

    const newEntry: GratitudeEntry = {
      id: crypto.randomUUID(),
      date: dateStr,
      content: gratitudeInput,
      createdAt: new Date().toISOString()
    };

    setGratitudeLogs(prev => [newEntry, ...prev]);
    setGratitudeInput('');
    // Reward for gratitude: XP +5, Soul +1
    updateStats(5, 'SOUL', 1);
  };

  const deleteGratitude = (id: string) => {
    if (confirm('Delete this gratitude entry? (Rewards will be deducted)')) {
      setGratitudeLogs(prev => prev.filter(g => g.id !== id));
      updateStats(-5, 'SOUL', -1);
    }
  };

  const openAddModal = (type: HabitType) => {
    setNewHabitType(type);
    setIsModalOpen(true);
  };

  if (loading) {
    return <div className="min-h-screen bg-slate-950 flex items-center justify-center text-slate-500">Loading...</div>;
  }

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  const radarData = Object.entries(stats.attributes).map(([key, value]) => ({
    subject: STAT_LABELS[key as StatType],
    A: value,
    fullMark: Math.max(...Object.values(stats.attributes)) * 1.2
  }));

  const isSelectedToday = isSameDay(selectedDate, new Date());
  const dateStr = format(selectedDate, 'yyyy-MM-dd');

  const goodHabits = habits.filter(h => h.type === 'good');
  const badHabits = habits.filter(h => h.type === 'bad');
  const dailyGratitudes = gratitudeLogs.filter(g => g.date === dateStr);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans pb-20">
      <ApiKeySelector onKeySelected={() => {}} />

      {/* Header */}
      <header className="bg-slate-900 border-b border-slate-800 sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <Trophy className="w-5 h-5 text-white" />
            </div>
            <span className="font-bold text-lg tracking-wide hidden sm:inline">Level Up Life</span>
          </div>

          <div className="flex items-center gap-4">
             <div className="text-sm text-slate-400 mr-2">
                Hello, <span className="text-white font-semibold">{user.username}</span>
             </div>
             <button
              onClick={() => setShowAvatarGen(!showAvatarGen)}
              className={`p-2 rounded-full transition-colors ${showAvatarGen ? 'bg-purple-500/20 text-purple-400' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
              title="Avatar Generator"
            >
              <Smile className="w-5 h-5" />
            </button>
            <button 
              onClick={handleLogout}
              className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors"
              title="Logout"
            >
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      {/* Avatar Generator Panel */}
      {showAvatarGen && (
        <div className="max-w-7xl mx-auto px-4 mt-6 animate-in slide-in-from-top-4 duration-300">
          <AvatarGenerator stats={stats} />
        </div>
      )}

      <main className="max-w-7xl mx-auto px-4 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Character Stats (Level, XP, Attributes) */}
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl relative overflow-hidden">
            {/* Ambient Background Effect */}
            <div className="absolute top-0 right-0 w-48 h-48 bg-indigo-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>

            <div className="relative z-10">
                <div className="flex items-center justify-between mb-2">
                    <h2 className="text-xl font-bold flex items-center gap-2">
                        <Sword className="w-5 h-5 text-indigo-400" />
                        Status
                    </h2>
                    <span className="bg-indigo-900/50 text-indigo-300 px-3 py-1 rounded-full text-xs font-mono border border-indigo-500/30">
                        Rank {Math.floor(stats.level / 10) + 1}
                    </span>
                </div>

                {/* Level Display */}
                <div className="flex flex-col items-center justify-center py-6">
                    <div className="relative">
                        <div className="w-24 h-24 rounded-full bg-slate-950 border-4 border-indigo-500/30 flex items-center justify-center shadow-[0_0_20px_rgba(99,102,241,0.2)]">
                            <span className="text-4xl font-black text-white">{stats.level}</span>
                        </div>
                        <div className="absolute -bottom-2 w-full text-center">
                            <span className="bg-indigo-600 text-white text-xs font-bold px-2 py-0.5 rounded-full uppercase tracking-wider shadow-lg">Level</span>
                        </div>
                    </div>
                </div>

                {/* XP Bar */}
                <div className="mb-8 bg-slate-950/50 p-4 rounded-xl border border-slate-800/50">
                    <div className="flex justify-between text-xs mb-2 text-slate-400 font-medium uppercase tracking-wide">
                        <span>Experience</span>
                        <span>{stats.currentXp} / {stats.nextLevelXp} XP</span>
                    </div>
                    <div className="w-full h-3 bg-slate-900 rounded-full overflow-hidden border border-slate-700">
                        <div 
                        className="h-full bg-gradient-to-r from-indigo-600 via-purple-500 to-indigo-400 shadow-[0_0_10px_rgba(99,102,241,0.5)] transition-all duration-700 ease-out relative"
                        style={{ width: `${Math.min(100, (stats.currentXp / stats.nextLevelXp) * 100)}%` }}
                        >
                            <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-b from-white/20 to-transparent"></div>
                        </div>
                    </div>
                </div>

                {/* Radar Chart */}
                <div className="h-[200px] w-full flex items-center justify-center -ml-2 mb-4">
                <ResponsiveContainer width="100%" height="100%">
                    <RadarChart cx="50%" cy="50%" outerRadius="65%" data={radarData}>
                    <PolarGrid stroke="#334155" />
                    <PolarAngleAxis dataKey="subject" tick={{ fill: '#94a3b8', fontSize: 12, fontWeight: 'bold' }} />
                    <PolarRadiusAxis angle={30} domain={[0, 'auto']} tick={false} axisLine={false} />
                    <Radar
                        name="Stats"
                        dataKey="A"
                        stroke="#818cf8"
                        fill="#6366f1"
                        fillOpacity={0.4}
                    />
                    <Tooltip 
                        contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9' }}
                        itemStyle={{ color: '#818cf8' }}
                    />
                    </RadarChart>
                </ResponsiveContainer>
                </div>

                {/* Attributes List */}
                <div className="space-y-2">
                {(Object.keys(stats.attributes) as StatType[]).map(key => (
                    <div key={key} className="bg-slate-950/50 p-2.5 rounded-lg border border-slate-800 flex justify-between items-center group hover:border-indigo-500/50 transition-colors">
                    <span className="text-sm text-slate-400 flex items-center gap-2 group-hover:text-slate-200">
                        {STAT_ICONS[key]} {STAT_LABELS[key]}
                    </span>
                    <span className="font-mono font-bold text-indigo-400 group-hover:text-indigo-300">{stats.attributes[key]}</span>
                    </div>
                ))}
                </div>
