import React, { useState } from 'react';
import { 
  eachDayOfInterval, 
  format, 
  isSameDay, 
  getDay, 
  endOfMonth, 
  endOfWeek, 
  addMonths, 
  isSameMonth
} from 'date-fns';
import { twMerge } from 'tailwind-merge';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { Habit, GratitudeEntry } from '../types';

// Local implementations to resolve missing export errors
const startOfMonth = (date: Date) => {
  const d = new Date(date);
  d.setDate(1);
  d.setHours(0, 0, 0, 0);
  return d;
};

const startOfWeek = (date: Date) => {
  const d = new Date(date);
  const day = d.getDay();
  const diff = d.getDate() - day;
  d.setDate(diff);
  d.setHours(0, 0, 0, 0);
  return d;
};

interface ContributionGraphProps {
  habits: Habit[];
  gratitudeLogs?: GratitudeEntry[]; 
  selectedDate: Date;
  onDateSelect: (date: Date) => void;
  theme?: 'emerald' | 'rose';
  title: string;
}

export const ContributionGraph: React.FC<ContributionGraphProps> = ({ 
  habits, 
  gratitudeLogs = [],
  selectedDate,
  onDateSelect,
  theme = 'emerald',
  title
}) => {
  const [viewDate, setViewDate] = useState(new Date());

  const handlePrevMonth = () => setViewDate(addMonths(viewDate, -1));
  const handleNextMonth = () => setViewDate(addMonths(viewDate, 1));

  // Calculate range for the view
  const monthStart = startOfMonth(viewDate);
  const monthEnd = endOfMonth(viewDate);
  const calendarStart = startOfWeek(monthStart);
  const calendarEnd = endOfWeek(monthEnd);

  const days = eachDayOfInterval({ start: calendarStart, end: calendarEnd });

  // Calculate intensity map
  const intensityMap = new Map<string, number>();

  days.forEach(day => {
    const dateStr = format(day, 'yyyy-MM-dd');
    let score = 0;

    // Count habits
    habits.forEach(habit => {
      if (habit.completedDates.includes(dateStr)) {
        score++;
      }
    });

    // Count gratitude
    const gratitudeCount = gratitudeLogs.filter(log => log.date === dateStr).length;
    score += gratitudeCount;

    intensityMap.set(dateStr, score);
  });

  const getColorClass = (count: number) => {
    if (count === 0) return 'bg-slate-800/50 hover:bg-slate-700';

    if (theme === 'rose') {
        if (count === 1) return 'bg-rose-900 hover:bg-rose-800';
        if (count === 2) return 'bg-rose-700 hover:bg-rose-600';
        if (count >= 3) return 'bg-rose-500 hover:bg-rose-400 shadow-[0_0_10px_rgba(244,63,94,0.4)]';
        return 'bg-rose-500';
    } else {
        if (count === 1) return 'bg-emerald-900 hover:bg-emerald-800';
        if (count === 2) return 'bg-emerald-700 hover:bg-emerald-600';
        if (count >= 3) return 'bg-emerald-500 hover:bg-emerald-400 shadow-[0_0_10px_rgba(16,185,129,0.4)]';
        return 'bg-emerald-500';
    }
  };

  // Group by weeks for the grid
  const weeks: Date[][] = [];
  let currentWeek: Date[] = [];

  days.forEach((day) => {
    if (getDay(day) === 0 && currentWeek.length > 0) {
      weeks.push(currentWeek);
      currentWeek = [];
    }
    currentWeek.push(day);
  });
  if (currentWeek.length > 0) weeks.push(currentWeek);

  return (
    <div className="w-full">
      <div className="flex items-center justify-between mb-6">
        <h3 className={`font-bold text-lg ${theme === 'rose' ? 'text-rose-400' : 'text-emerald-400'}`}>
          {title}
        </h3>
        <div className="flex items-center gap-4 bg-slate-950 rounded-lg p-1 border border-slate-800">
          <button onClick={handlePrevMonth} className="p-1 hover:bg-slate-800 rounded text-slate-400 hover:text-white">
            <ChevronLeft className="w-5 h-5" />
          </button>
          <span className="text-sm font-bold min-w-[100px] text-center text-slate-200">
            {format(viewDate, 'MMMM yyyy')}
          </span>
          <button onClick={handleNextMonth} className="p-1 hover:bg-slate-800 rounded text-slate-400 hover:text-white">
            <ChevronRight className="w-5 h-5" />
          </button>
        </div>
      </div>

      <div className="w-full overflow-x-auto pb-4 custom-scrollbar">
        <div className="flex gap-2 min-w-max justify-center">
          {weeks.map((week, weekIndex) => (
            <div key={weekIndex} className="flex flex-col gap-2">
              {week.map((day) => {
                const dateStr = format(day, 'yyyy-MM-dd');
                const count = intensityMap.get(dateStr) || 0;
                const isSelected = isSameDay(day, selectedDate);
                const isToday = isSameDay(day, new Date());
                const inCurrentMonth = isSameMonth(day, viewDate);

                return (
                  <div
                    key={dateStr}
                    onClick={() => onDateSelect(day)}
                    title={`${dateStr}: ${count} entries`}
                    className={twMerge(
                      "w-8 h-8 rounded-md cursor-pointer transition-all duration-200 border border-transparent flex items-center justify-center relative",
                      getColorClass(count),
                      !inCurrentMonth && "opacity-30 grayscale",
                      isSelected && "ring-2 ring-white border-transparent z-10 scale-110 shadow-lg",
                      isToday && !isSelected && "border-indigo-500/50"
                    )}
                  >
                    <span className={`text-[10px] ${count > 0 ? 'text-white/90' : 'text-slate-600'}`}>
                      {format(day, 'd')}
                    </span>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>

      <div className="flex justify-center items-center gap-3 mt-4 text-xs text-slate-500">
        <span>Less</span>
        <div className="w-4 h-4 bg-slate-800 rounded"></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-900' : 'bg-emerald-900'}`}></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-700' : 'bg-emerald-700'}`}></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-500' : 'bg-emerald-500'}`}></div>
        <span>More</span>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer,
  Tooltip
} from 'recharts';
import { Plus, Check, Trash2, Trophy, Zap, Brain, Activity, Smile, Sword, Calendar, LogOut, Skull, AlertCircle, Heart, Send } from 'lucide-react';
import { format, isSameDay } from 'date-fns';
import { Habit, UserStats, StatType, STAT_LABELS, User, HabitType, GratitudeEntry } from './types';
import { Login } from './components/Login';
import { ContributionGraph } from './components/ContributionGraph';
import { MockDB } from './services/db';
import { ApiKeySelector } from './components/ApiKeySelector';
import { AvatarGenerator } from './components/AvatarGenerator';

const STAT_ICONS: Record<StatType, React.ReactNode> = {
  BODY: <Activity className="w-4 h-4" />,
  MIND: <Brain className="w-4 h-4" />,
  SOUL: <Heart className="w-4 h-4" />,
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [gratitudeLogs, setGratitudeLogs] = useState<GratitudeEntry[]>([]);
  const [stats, setStats] = useState<UserStats>({
    level: 1, currentXp: 0, nextLevelXp: 100,
    attributes: { BODY: 1, MIND: 1, SOUL: 1 }
  });

  // UI State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [showAvatarGen, setShowAvatarGen] = useState(false);

  // Dashboard view state: 'positive' or 'negative'
  const [dashboardView, setDashboardView] = useState<'positive' | 'negative'>('positive');

  // Form State
  const [newHabitTitle, setNewHabitTitle] = useState('');
  const [newHabitStat, setNewHabitStat] = useState<StatType>('BODY');
  const [newHabitType, setNewHabitType] = useState<HabitType>('good');
  const [gratitudeInput, setGratitudeInput] = useState('');

  // Check for existing session
  useEffect(() => {
    const savedUser = localStorage.getItem('rpg_current_user');
    if (savedUser) {
      handleLogin(savedUser);
    } else {
      setLoading(false);
    }
  }, []);

  const handleLogin = async (username: string) => {
    setLoading(true);
    const data = await MockDB.login(username);
    const migratedHabits = data.habits.map(h => ({ ...h, type: h.type || 'good' }));
    setHabits(migratedHabits);
    setGratitudeLogs(data.gratitudeLogs || []);
    setStats(data.stats);
    setUser({ username, isLoggedIn: true });
    localStorage.setItem('rpg_current_user', username);
    setLoading(false);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('rpg_current_user');
    setHabits([]);
    setGratitudeLogs([]);
  };

  // Auto-save whenever data changes
  useEffect(() => {
    if (user) {
      MockDB.save(user.username, { habits, gratitudeLogs, stats });
    }
  }, [habits, gratitudeLogs, stats, user]);

  const addHabit = () => {
    if (!newHabitTitle.trim()) return;

    const newHabit: Habit = {
      id: crypto.randomUUID(),
      title: newHabitTitle,
      type: newHabitType,
      stat: newHabitStat,
      xpReward: 10,
      statReward: 1,
      completedDates: [],
      streak: 0,
      createdAt: new Date().toISOString()
    };

    setHabits([...habits, newHabit]);
    setNewHabitTitle('');
    setIsModalOpen(false);
  };

  const deleteHabit = (id: string) => {
    if (confirm('Are you sure you want to delete this habit? History will be kept but it will disappear from the list.')) {
       setHabits(habits.filter(h => h.id !== id));
    }
  };

  const updateStats = (xpChange: number, stat: StatType, statChange: number) => {
    setStats(prevStats => {
      let newXp = Math.max(0, prevStats.currentXp + xpChange);
      let newAttributes = { ...prevStats.attributes };
      newAttributes[stat] = Math.max(1, newAttributes[stat] + statChange);

      let newLevel = prevStats.level;
      let nextXp = prevStats.nextLevelXp;

      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }

      return {
        ...prevStats,
        level: newLevel,
        currentXp: newXp,
        nextLevelXp: nextXp,
        attributes: newAttributes
      };
    });
  };

  const toggleHabitCompletion = (id: string) => {
    const dateStr = format(selectedDate, 'yyyy-MM-dd');

    setHabits(prevHabits => {
      const habit = prevHabits.find(h => h.id === id);
      if (!habit) return prevHabits;

      const isCompleted = habit.completedDates.includes(dateStr);
      let newCompletedDates: string[];
      let xpChange = 0;
      let statChange = 0;

      const multiplier = habit.type === 'good' ? 1 : -1;

      if (isCompleted) {
        // Undoing
        newCompletedDates = habit.completedDates.filter(d => d !== dateStr);
        xpChange = -1 * habit.xpReward * multiplier;
        statChange = -1 * habit.statReward * multiplier;
      } else {
        // Doing
        newCompletedDates = [...habit.completedDates, dateStr];
        xpChange = habit.xpReward * multiplier;
        statChange = habit.statReward * multiplier;
      }

      updateStats(xpChange, habit.stat, statChange);

      return prevHabits.map(h => 
        h.id === id 
          ? { ...h, completedDates: newCompletedDates } 
          : h
      );
    });
  };

  const addGratitude = () => {
    if (!gratitudeInput.trim()) return;
    const dateStr = format(selectedDate, 'yyyy-MM-dd');

    const newEntry: GratitudeEntry = {
      id: crypto.randomUUID(),
      date: dateStr,
      content: gratitudeInput,
      createdAt: new Date().toISOString()
    };

    setGratitudeLogs(prev => [newEntry, ...prev]);
    setGratitudeInput('');
    // Reward for gratitude: XP +5, Soul +1
    updateStats(5, 'SOUL', 1);
  };

  const deleteGratitude = (id: string) => {
    if (confirm('Delete this gratitude entry? (Rewards will be deducted)')) {
      setGratitudeLogs(prev => prev.filter(g => g.id !== id));
      updateStats(-5, 'SOUL', -1);
    }
  };

  const openAddModal = (type: HabitType) => {
    setNewHabitType(type);
    setIsModalOpen(true);
  };

  if (loading) {
    return <div className="min-h-screen bg-slate-950 flex items-center justify-center text-slate-500">Loading...</div>;
  }

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  const radarData = Object.entries(stats.attributes).map(([key, value]) => ({
    subject: STAT_LABELS[key as StatType],
    A: value,
    fullMark: Math.max(...Object.values(stats.attributes)) * 1.2
  }));

  const isSelectedToday = isSameDay(selectedDate, new Date());
  const dateStr = format(selectedDate, 'yyyy-MM-dd');

  const goodHabits = habits.filter(h => h.type === 'good');
  const badHabits = habits.filter(h => h.type === 'bad');
  const dailyGratitudes = gratitudeLogs.filter(g => g.date === dateStr);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans pb-20">
      <ApiKeySelector onKeySelected={() => {}} />

      {/* Header */}
      <header className="bg-slate-900 border-b border-slate-800 sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-[#ff6b35] rounded flex items-center justify-center shadow-lg shadow-[#ff6b35]/20">
              <Trophy className="w-5 h-5 text-white" />
            </div>
            <span className="font-bold text-lg tracking-wide hidden sm:inline">Level Up Life</span>
          </div>

          <div className="flex items-center gap-4">
             <div className="text-sm text-slate-400 mr-2">
                Hello, <span className="text-white font-semibold">{user.username}</span>
             </div>
             <button
              onClick={() => setShowAvatarGen(!showAvatarGen)}
              className={`p-2 rounded-full transition-colors ${showAvatarGen ? 'bg-[#ff6b35]/20 text-[#ff6b35]' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
              title="Avatar Generator"
            >
              <Smile className="w-5 h-5" />
            </button>
            <button 
              onClick={handleLogout}
              className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors"
              title="Logout"
            >
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      {/* Avatar Generator Panel */}
      {showAvatarGen && (
        <div className="max-w-7xl mx-auto px-4 mt-6 animate-in slide-in-from-top-4 duration-300">
          <AvatarGenerator stats={stats} />
        </div>
      )}

      <main className="max-w-7xl mx-auto px-4 py-8 space-y-8">

        {/* Top Section: Character Stats Summary */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Level & XP Card - Square Layout */}
          <div className="aspect-square bg-slate-900 rounded-2xl border border-slate-800 p-8 shadow-xl relative overflow-hidden flex flex-col items-center justify-center text-center">
             {/* Background Decoration */}
