import { doc, getDoc, setDoc } from 'firebase/firestore';
import { db } from './firebase';
import { AppData, UserStats } from '../types';

const INITIAL_STATS: UserStats = {
  level: 1,
  currentXp: 0,
  nextLevelXp: 100,
  attributes: {
    BODY: 1,
    MIND: 1,
    SOUL: 1,
  },
};

const INITIAL_DATA: AppData = {
  habits: [],
  gratitudeLogs: [],
  stats: INITIAL_STATS,
};

export class DatabaseService {
  /**
   * Fetches user data from Firestore. 
   * If the document doesn't exist (new user), it returns initial data.
   */
  static async getUserData(uid: string): Promise<AppData> {
    try {
      const userDocRef = doc(db, 'users', uid);
      const docSnap = await getDoc(userDocRef);

      if (docSnap.exists()) {
        const data = docSnap.data() as Partial<AppData>;

        // Safe deep merge for stats to prevent missing attributes
        const savedStats = data.stats || {};
        const mergedStats: UserStats = {
            ...INITIAL_STATS,
            ...savedStats,
            attributes: {
                ...INITIAL_STATS.attributes,
                ...(savedStats.attributes || {})
            }
        };

        // Merge with initial data to ensure all fields exist
        return {
          ...INITIAL_DATA,
          ...data,
          stats: mergedStats
        };
      } else {
        // New user, create initial doc
        await setDoc(userDocRef, INITIAL_DATA);
        return INITIAL_DATA;
      }
    } catch (error) {
      console.error("Error fetching user data:", error);
      throw error;
    }
  }

  /**
   * Saves user data to Firestore.
   * Uses merge: true to avoid overwriting fields not passed (though we usually pass full object).
   */
  static async saveUserData(uid: string, data: Partial<AppData>): Promise<void> {
    try {
      const userDocRef = doc(db, 'users', uid);
      await setDoc(userDocRef, data, { merge: true });
    } catch (error) {
      console.error("Error saving user data:", error);
      // We don't throw here to avoid crashing the UI on auto-save, but you might want to show a toast
    }
  }
}

