import React, { useState, useEffect } from 'react';
import { 
  Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer,
  Tooltip
} from 'recharts';
import { Plus, Check, Trash2, Trophy, Zap, Brain, Activity, Sword, Calendar, LogOut, Skull, AlertCircle, Heart, Send, ChevronDown, ChevronUp, Flame } from 'lucide-react';
