import { endOfWeek, endOfMonth, eachDayOfInterval, format } from 'date-fns';
import { BarChart3 } from 'lucide-react';

interface HabitStatsProps {
  habits: Habit[];
  selectedDate: Date;
}

// Local implementations for missing date-fns exports
const startOfWeek = (date: Date) => {
  const d = new Date(date);
  const day = d.getDay();
  const diff = d.getDate() - day;
  d.setDate(diff);
  d.setHours(0, 0, 0, 0);
  return d;
};

const startOfMonth = (date: Date) => {
  const d = new Date(date);
  d.setDate(1);
  d.setHours(0, 0, 0, 0);
  return d;
};

export const HabitStats: React.FC<HabitStatsProps> = ({ habits, selectedDate }) => {
  const [view, setView] = useState<'week' | 'month'>('week');

  const goodHabits = habits.filter(h => h.type === 'good');

  // Calculate stats based on view
  const calculateData = () => {
    let start: Date, end: Date;

    if (view === 'week') {
      start = startOfWeek(selectedDate);
      end = endOfWeek(selectedDate);
    } else {
      start = startOfMonth(selectedDate);
      end = endOfMonth(selectedDate);
    }

    const intervalDays = eachDayOfInterval({ start, end });
    const maxCount = intervalDays.length;

    return goodHabits.map(habit => {
      const count = intervalDays.reduce((acc, day) => {
        const dateStr = format(day, 'yyyy-MM-dd');
        return acc + (habit.completedDates.includes(dateStr) ? 1 : 0);
      }, 0);

      return {
        name: habit.title,
        count: count,
        max: maxCount,
        fill: '#ff6b35'
      };
    });
  };

  const data = calculateData();

  return (
    <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl flex flex-col h-full min-h-[400px]">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-xl font-bold text-white flex items-center gap-2">
          <BarChart3 className="w-5 h-5 text-[#ff6b35]" />
          Completion Stats
        </h2>

        <div className="flex gap-2 bg-slate-950 p-1 rounded-lg border border-slate-800">
           <button
             onClick={() => setView('week')}
             className={`px-3 py-1 text-xs font-bold rounded transition-colors ${
               view === 'week' ? 'bg-[#ff6b35] text-white' : 'text-slate-500 hover:text-white'
             }`}
           >
             This Week
           </button>
           <button
             onClick={() => setView('month')}
             className={`px-3 py-1 text-xs font-bold rounded transition-colors ${
               view === 'month' ? 'bg-[#ff6b35] text-white' : 'text-slate-500 hover:text-white'
             }`}
           >
             This Month
           </button>
        </div>
      </div>

      {goodHabits.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center text-slate-500 space-y-4">
          <div className="w-16 h-16 bg-slate-950 rounded-full flex items-center justify-center border border-slate-800">
            <BarChart3 className="w-8 h-8 opacity-20" />
          </div>
          <p className="text-sm">Add habits to see your progress chart here.</p>
        </div>
      ) : (
        <>
          <div className="flex-1 w-full min-h-0">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={data} layout="vertical" margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="#334155" horizontal={false} />
                <XAxis type="number" hide domain={[0, 'dataMax']} />
                <YAxis 
                  dataKey="name" 
                  type="category" 
                  width={100} 
                  tick={{ fill: '#94a3b8', fontSize: 12 }} 
                  interval={0}
                />
                <Tooltip 
                  cursor={{ fill: '#1e293b' }}
                  contentStyle={{ backgroundColor: '#0f172a', borderColor: '#334155', color: '#f1f5f9', borderRadius: '8px', border: '1px solid #334155' }}
                  formatter={(value: number) => [value, 'Completed']}
                />
                <Bar dataKey="count" radius={[0, 4, 4, 0]} barSize={20}>
                  {data.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.count > 0 ? '#ff6b35' : '#334155'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>

          <p className="text-center text-xs text-slate-500 mt-4 border-t border-slate-800/50 pt-4">
            Showing total completions for the selected period.
          </p>
        </>
      )}
    </div>
  );
};

