import { doc, getDoc, setDoc } from 'firebase/firestore';
import { db } from './firebase';
import { AppData, UserStats } from '../types';

const INITIAL_STATS: UserStats = {
  level: 1,
  currentXp: 0,
  nextLevelXp: 100,
  attributes: {
    BODY: 1,
    MIND: 1,
    SOUL: 1,
  },
};

const INITIAL_DATA: AppData = {
  habits: [],
  gratitudeLogs: [],
  stats: INITIAL_STATS,
};

export const getUserData = async (uid: string): Promise<AppData> => {
  try {
    const docRef = doc(db, "users", uid);
    const docSnap = await getDoc(docRef);

    if (docSnap.exists()) {
      const data = docSnap.data() as Partial<AppData>;
      // Merge with initial data structure to ensure all fields exist (schema migration safe)
      return {
        habits: data.habits || [],
        gratitudeLogs: data.gratitudeLogs || [],
        stats: data.stats || INITIAL_STATS,
      };
    } else {
      // Create new user document for first-time login
      await setDoc(docRef, INITIAL_DATA);
      return INITIAL_DATA;
    }
  } catch (error) {
    console.error("Error fetching user data:", error);
    // Return initial data on error to prevent app crash, though this means offline mode isn't fully supported without more logic
    return INITIAL_DATA;
  }
};

export const saveUserData = async (uid: string, data: AppData): Promise<void> => {
  try {
    const docRef = doc(db, "users", uid);
    // Use merge: true to avoid overwriting fields if we add new ones later, 
    // though here we likely want to sync the whole state.
    await setDoc(docRef, data, { merge: true });
  } catch (error) {
    console.error("Error saving user data:", error);
  }
};

