import React, { useState } from 'react';
import { 
  eachDayOfInterval, 
  format, 
  isSameDay, 
  getDay, 
  endOfMonth, 
  endOfWeek, 
  addMonths, 
  isSameMonth,
  startOfMonth,
  startOfWeek
} from 'date-fns';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip as RechartsTooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { twMerge } from 'tailwind-merge';
import { ChevronLeft, ChevronRight, CalendarDays, BarChart3 } from 'lucide-react';
import { Habit, GratitudeEntry } from '../types';

interface ContributionGraphProps {
  habits: Habit[];
  gratitudeLogs?: GratitudeEntry[]; 
  selectedDate: Date;
  onDateSelect: (date: Date) => void;
  theme?: 'emerald' | 'rose';
  title: string;
}

export const ContributionGraph: React.FC<ContributionGraphProps> = ({ 
  habits, 
  gratitudeLogs = [],
  selectedDate,
  onDateSelect,
  theme = 'emerald',
  title
}) => {
  const [viewDate, setViewDate] = useState(new Date());
  const [viewType, setViewType] = useState<'month' | 'week'>('month');

  const handlePrev = () => {
    if (viewType === 'month') {
      setViewDate(prev => addMonths(prev, -1));
    } else {
      // For week view, we rely on selectedDate to determine the week, 
      // but here we just shift the viewDate to keep month navigation context
      setViewDate(prev => addMonths(prev, -1)); 
    }
  };

  const handleNext = () => {
    if (viewType === 'month') {
      setViewDate(prev => addMonths(prev, 1));
    } else {
      setViewDate(prev => addMonths(prev, 1));
    }
  };

  // --- Data Preparation ---
  const intensityMap = new Map<string, number>();

  // Calculate stats for a broad range (current month view context)
  const monthStart = startOfMonth(viewDate);
  const monthEnd = endOfMonth(viewDate);
  const calendarStart = startOfWeek(monthStart);
  const calendarEnd = endOfWeek(monthEnd);

  const days = eachDayOfInterval({ start: calendarStart, end: calendarEnd });

  days.forEach(day => {
    const dateStr = format(day, 'yyyy-MM-dd');
    let score = 0;

    // Count habits
    habits.forEach(habit => {
      if (habit.completedDates.includes(dateStr)) {
        score++;
      }
    });

    // Count gratitude
    const gratitudeCount = gratitudeLogs.filter(log => log.date === dateStr).length;
    score += gratitudeCount;

    intensityMap.set(dateStr, score);
  });

  // --- Helper for Colors ---
  const getColorClass = (count: number) => {
    if (count === 0) return 'bg-slate-800/50 hover:bg-slate-700';

    if (theme === 'rose') {
        if (count === 1) return 'bg-rose-900 hover:bg-rose-800';
        if (count === 2) return 'bg-rose-700 hover:bg-rose-600';
        if (count >= 3) return 'bg-rose-500 hover:bg-rose-400 shadow-[0_0_10px_rgba(244,63,94,0.4)]';
        return 'bg-rose-500';
    } else {
        // Orange theme
        if (count === 1) return 'bg-[#ff6b35]/30 hover:bg-[#ff6b35]/40';
        if (count === 2) return 'bg-[#ff6b35]/60 hover:bg-[#ff6b35]/70';
        if (count >= 3) return 'bg-[#ff6b35] hover:bg-[#ff8f66] shadow-[0_0_10px_rgba(255,107,53,0.4)]';
        return 'bg-[#ff6b35]';
    }
  };

  const getBarColor = () => theme === 'rose' ? '#f43f5e' : '#ff6b35';

  // --- Render Logic ---

  // 1. Weekly View (Bar Chart)
  if (viewType === 'week') {
    // Determine the week based on selectedDate
    const weekStart = startOfWeek(selectedDate);
    const weekEnd = endOfWeek(selectedDate);
    const weekDays = eachDayOfInterval({ start: weekStart, end: weekEnd });

    const chartData = weekDays.map(day => {
      const dateStr = format(day, 'yyyy-MM-dd');
      return {
        day: format(day, 'EEE'), // Mon, Tue...
        fullDate: dateStr,
        score: intensityMap.get(dateStr) || 0,
        originalDate: day
      };
    });

    return (
       <div className="w-full h-full min-h-[200px] flex flex-col">
        <div className="flex items-center justify-between mb-6">
          <h3 className={`font-bold text-lg ${theme === 'rose' ? 'text-rose-400' : 'text-[#ff6b35]'} flex items-center gap-2`}>
            {title} <span className="text-slate-500 text-sm font-normal">| Weekly</span>
          </h3>
          <div className="flex gap-2 bg-slate-950 p-1 rounded-lg border border-slate-800">
             <button 
                onClick={() => setViewType('month')}
                className="p-1.5 rounded text-slate-400 hover:text-white transition-colors"
                title="Month View"
             >
                <CalendarDays className="w-4 h-4" />
             </button>
             <button 
                onClick={() => setViewType('week')}
                className={`p-1.5 rounded transition-colors ${theme === 'rose' ? 'bg-rose-900/50 text-white' : 'bg-[#ff6b35]/20 text-white'}`}
                title="Week View"
             >
                <BarChart3 className="w-4 h-4" />
             </button>
          </div>
        </div>

        <div className="flex-1 w-full min-h-[180px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
              <XAxis 
                dataKey="day" 
                tick={{ fill: '#94a3b8', fontSize: 12 }} 
                axisLine={false} 
                tickLine={false} 
              />
              <YAxis 
                tick={{ fill: '#94a3b8', fontSize: 12 }} 
                axisLine={false} 
                tickLine={false}
                allowDecimals={false}
              />
              <RechartsTooltip 
                cursor={{ fill: '#1e293b' }}
