export const supabase = createClient(DB_URL, DB_KEY);

/**
 * SQL Setup Instructions:
 * 
 * Please run this SQL in your Supabase/Postgres Query Editor to create the table:
 * 
 * create table user_data (
 *   id uuid references auth.users not null primary key,
 *   username text,
 *   habits jsonb default '[]'::jsonb,
 *   gratitude_logs jsonb default '[]'::jsonb,
 *   stats jsonb default '{}'::jsonb,
 *   updated_at timestamp with time zone default timezone('utc'::text, now())
 * );
 * 
 * alter table user_data enable row level security;
 * create policy "Users can view own data" on user_data for select using (auth.uid() = id);
 * create policy "Users can update own data" on user_data for update using (auth.uid() = id);
 * create policy "Users can insert own data" on user_data for insert with check (auth.uid() = id);
 */

import { supabase } from './postgresConfig';
import { AppData, UserStats } from '../types';

const INITIAL_STATS: UserStats = {
  level: 1,
  currentXp: 0,
  nextLevelXp: 100,
  attributes: {
    BODY: 1,
    MIND: 1,
    SOUL: 1,
  },
};

const INITIAL_DATA: AppData = {
  habits: [],
  gratitudeLogs: [],
  stats: INITIAL_STATS,
};

export const DB = {
  /**
   * Fetch user data from the 'user_data' table in Postgres
   */
  async getUserData(userId: string): Promise<AppData> {
    try {
      const { data, error } = await supabase
        .from('user_data')
        .select('habits, gratitude_logs, stats')
        .eq('id', userId)
        .single();

      if (error && error.code !== 'PGRST116') { // PGRST116 is "Row not found"
        console.error("Postgres Read Error:", error);
        return INITIAL_DATA;
      }

      if (data) {
        return {
          habits: data.habits || [],
          gratitudeLogs: data.gratitude_logs || [],
          stats: data.stats || INITIAL_STATS
        };
      }

      // If user exists in Auth but not in Table, return initial data
      return INITIAL_DATA;
    } catch (err) {
      console.error("DB Error:", err);
      return INITIAL_DATA;
    }
  },

  /**
   * Save (Upsert) user data to the 'user_data' table
   */
  async saveUserData(userId: string, username: string, data: AppData): Promise<void> {
    try {
      const { error } = await supabase
        .from('user_data')
        .upsert({
          id: userId,
          username: username,
          habits: data.habits,
          gratitude_logs: data.gratitudeLogs,
          stats: data.stats,
          updated_at: new Date().toISOString()
        });

      if (error) {
        console.error("Postgres Write Error:", error);
      }
    } catch (err) {
      console.error("DB Save Error:", err);
    }
  }
};

