import { db } from './firebaseConfig';
import { doc, getDoc, setDoc } from 'firebase/firestore';
import { AppData, UserStats } from '../types';

const INITIAL_STATS: UserStats = {
  level: 1,
  currentXp: 0,
  nextLevelXp: 100,
  attributes: {
    BODY: 1,
    MIND: 1,
    SOUL: 1,
  },
};

const INITIAL_DATA: AppData = {
  habits: [],
  gratitudeLogs: [],
  stats: INITIAL_STATS,
};

export const DB = {
  /**
   * Fetch user data from Firestore 'users' collection
   */
  async getUserData(userId: string): Promise<AppData> {
    try {
      const docRef = doc(db, "users", userId);
      const docSnap = await getDoc(docRef);

      if (docSnap.exists()) {
        const data = docSnap.data();
        return {
          habits: data.habits || [],
          gratitudeLogs: data.gratitudeLogs || [],
          stats: data.stats || INITIAL_STATS
        };
      }

      // User exists in Auth but not in DB yet, return defaults
      return INITIAL_DATA;
    } catch (err) {
      console.error("Firestore Read Error:", err);
      return INITIAL_DATA;
    }
  },

  /**
   * Save (Set/Merge) user data to Firestore
   */
  async saveUserData(userId: string, username: string, data: AppData): Promise<void> {
    try {
      const docRef = doc(db, "users", userId);
      await setDoc(docRef, {
        username,
        habits: data.habits,
        gratitudeLogs: data.gratitudeLogs,
        stats: data.stats,
        lastUpdated: new Date().toISOString()
      }, { merge: true });
    } catch (err) {
      console.error("Firestore Save Error:", err);
    }
  }
};

import React, { useState } from 'react';
import { Sword, LogIn, UserPlus, Mail, Lock, AlertCircle, User as UserIcon } from 'lucide-react';
