          <p className="text-slate-400 mt-2">
            {isRegistering ? "Join the Guild" : "Welcome Back, Hero"}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          {error && (
            <div className="bg-red-500/10 border border-red-500/50 text-red-400 text-sm p-3 rounded-lg flex items-center gap-2">
              <AlertCircle className="w-4 h-4" />
              {error}
            </div>
          )}

          {isRegistering && (
            <div>
              <label className="block text-xs font-medium text-slate-400 mb-1 ml-1">
                Adventurer Name
              </label>
              <div className="relative">
                <UserIcon className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
                <input
                  type="text"
                  required
