import { db } from './firebaseConfig';
import { doc, getDoc, setDoc } from 'firebase/firestore';
import { AppData, UserStats } from '../types';

const INITIAL_STATS: UserStats = {
  level: 1,
  currentXp: 0,
  nextLevelXp: 100,
  attributes: {
    BODY: 1,
    MIND: 1,
    SOUL: 1,
  },
};

const INITIAL_DATA: AppData = {
  habits: [],
  gratitudeLogs: [],
  stats: INITIAL_STATS,
};

export const DB = {
  /**
   * Fetch user data from Firestore 'users' collection
   */
  async getUserData(userId: string): Promise<AppData> {
    try {
      const docRef = doc(db, "users", userId);
      const docSnap = await getDoc(docRef);

      if (docSnap.exists()) {
        const data = docSnap.data();
        return {
          habits: data.habits || [],
          gratitudeLogs: data.gratitudeLogs || [],
          stats: data.stats || INITIAL_STATS
        };
      }

      // Return defaults for new users (client-side will handle saving later)
      return INITIAL_DATA;
    } catch (err) {
      console.error("Firestore Read Error:", err);
      return INITIAL_DATA;
    }
  },

  /**
   * Save (Set/Merge) user data to Firestore
   */
  async saveUserData(userId: string, username: string, data: AppData): Promise<void> {
    try {
      const docRef = doc(db, "users", userId);
      await setDoc(docRef, {
        username,
        habits: data.habits,
        gratitudeLogs: data.gratitudeLogs,
        stats: data.stats,
        lastUpdated: new Date().toISOString()
      }, { merge: true });
    } catch (err) {
      console.error("Firestore Save Error:", err);
    }
  }
};

import React, { useState } from 'react';
import { 
  eachDayOfInterval, 
  format, 
  isSameDay, 
  getDay, 
  endOfMonth, 
  endOfWeek, 
  addMonths, 
  isSameMonth,
  startOfMonth,
  startOfWeek
} from 'date-fns';
import { twMerge } from 'tailwind-merge';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { Habit, GratitudeEntry } from '../types';

interface ContributionGraphProps {
  habits: Habit[];
  gratitudeLogs?: GratitudeEntry[]; 
  selectedDate: Date;
  onDateSelect: (date: Date) => void;
  theme?: 'emerald' | 'rose';
  title: string;
}

export const ContributionGraph: React.FC<ContributionGraphProps> = ({ 
  habits, 
  gratitudeLogs = [],
  selectedDate,
  onDateSelect,
  theme = 'emerald',
  title
}) => {
  const [viewDate, setViewDate] = useState(new Date());

  const handlePrevMonth = () => setViewDate(addMonths(viewDate, -1));
  const handleNextMonth = () => setViewDate(addMonths(viewDate, 1));

  // Calculate range for the view
  const monthStart = startOfMonth(viewDate);
  const monthEnd = endOfMonth(viewDate);
  const calendarStart = startOfWeek(monthStart);
  const calendarEnd = endOfWeek(monthEnd);

  const days = eachDayOfInterval({ start: calendarStart, end: calendarEnd });

  // Calculate intensity map
  const intensityMap = new Map<string, number>();

  days.forEach(day => {
    const dateStr = format(day, 'yyyy-MM-dd');
    let score = 0;

    // Count habits
    habits.forEach(habit => {
      if (habit.completedDates.includes(dateStr)) {
        score++;
      }
    });

    // Count gratitude
    const gratitudeCount = gratitudeLogs.filter(log => log.date === dateStr).length;
    score += gratitudeCount;

    intensityMap.set(dateStr, score);
  });

  const getColorClass = (count: number) => {
    if (count === 0) return 'bg-slate-800/50 hover:bg-slate-700';

    if (theme === 'rose') {
        if (count === 1) return 'bg-rose-900 hover:bg-rose-800';
        if (count === 2) return 'bg-rose-700 hover:bg-rose-600';
        if (count >= 3) return 'bg-rose-500 hover:bg-rose-400 shadow-[0_0_10px_rgba(244,63,94,0.4)]';
        return 'bg-rose-500';
    } else {
        // Updated to use #ff6b35 (Orange) instead of Emerald
        if (count === 1) return 'bg-[#ff6b35]/30 hover:bg-[#ff6b35]/40';
        if (count === 2) return 'bg-[#ff6b35]/60 hover:bg-[#ff6b35]/70';
        if (count >= 3) return 'bg-[#ff6b35] hover:bg-[#ff8f66] shadow-[0_0_10px_rgba(255,107,53,0.4)]';
        return 'bg-[#ff6b35]';
    }
  };

  // Group by weeks for the grid
  const weeks: Date[][] = [];
  let currentWeek: Date[] = [];

  days.forEach((day) => {
    if (getDay(day) === 0 && currentWeek.length > 0) {
      weeks.push(currentWeek);
      currentWeek = [];
    }
    currentWeek.push(day);
  });
  if (currentWeek.length > 0) weeks.push(currentWeek);

  return (
    <div className="w-full">
      <div className="flex items-center justify-between mb-6">
        <h3 className={`font-bold text-lg ${theme === 'rose' ? 'text-rose-400' : 'text-[#ff6b35]'}`}>
          {title}
        </h3>
        <div className="flex items-center gap-4 bg-slate-950 rounded-lg p-1 border border-slate-800">
          <button onClick={handlePrevMonth} className="p-1 hover:bg-slate-800 rounded text-slate-400 hover:text-white">
            <ChevronLeft className="w-5 h-5" />
          </button>
          <span className="text-sm font-bold min-w-[100px] text-center text-slate-200">
            {format(viewDate, 'MMMM yyyy')}
          </span>
          <button onClick={handleNextMonth} className="p-1 hover:bg-slate-800 rounded text-slate-400 hover:text-white">
            <ChevronRight className="w-5 h-5" />
          </button>
        </div>
      </div>

      <div className="w-full overflow-x-auto pb-4 custom-scrollbar">
        <div className="flex gap-2 min-w-max justify-center">
          {weeks.map((week, weekIndex) => (
            <div key={weekIndex} className="flex flex-col gap-2">
              {week.map((day) => {
                const dateStr = format(day, 'yyyy-MM-dd');
                const count = intensityMap.get(dateStr) || 0;
                const isSelected = isSameDay(day, selectedDate);
                const isToday = isSameDay(day, new Date());
                const inCurrentMonth = isSameMonth(day, viewDate);

                return (
                  <div
                    key={dateStr}
                    onClick={() => onDateSelect(day)}
                    title={`${dateStr}: ${count} entries`}
                    className={twMerge(
                      "w-12 h-12 rounded-lg cursor-pointer transition-all duration-200 border border-transparent flex items-center justify-center relative",
                      getColorClass(count),
                      !inCurrentMonth && "opacity-20 grayscale",
                      isSelected && "ring-2 ring-white border-transparent z-10 scale-110 shadow-lg",
                      isToday && !isSelected && "border-[#ff6b35]/80"
                    )}
                  >
                    <span className={`text-xs font-medium ${count > 0 ? 'text-white/90' : 'text-slate-600'}`}>
                      {format(day, 'd')}
                    </span>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>

      <div className="flex justify-center items-center gap-3 mt-4 text-xs text-slate-500">
        <span>Less</span>
        <div className="w-4 h-4 bg-slate-800 rounded"></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-900' : 'bg-[#ff6b35]/30'}`}></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-700' : 'bg-[#ff6b35]/60'}`}></div>
        <div className={`w-4 h-4 rounded ${theme === 'rose' ? 'bg-rose-500' : 'bg-[#ff6b35]'}`}></div>
        <span>More</span>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Sword, LogIn, UserPlus, Mail, Lock, AlertCircle, User as UserIcon } from 'lucide-react';
import { createUserWithEmailAndPassword, signInWithEmailAndPassword, updateProfile } from 'firebase/auth';
import { auth } from '../services/firebaseConfig';
import { DB } from '../services/db';

interface LoginProps {
  onLoginSuccess: () => void;
}

export const Login: React.FC<LoginProps> = ({ onLoginSuccess }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [username, setUsername] = useState(''); 
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
      if (isRegistering) {
        // --- REGISTER ---
        const userCredential = await createUserWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;

        // Set Display Name in Firebase Auth
        await updateProfile(user, {
          displayName: username
        });

        // Initialize Firestore Data with default stats
        await DB.saveUserData(user.uid, username, {
          habits: [],
          gratitudeLogs: [],
          stats: {
             level: 1, currentXp: 0, nextLevelXp: 100,
             attributes: { BODY: 1, MIND: 1, SOUL: 1 }
          }
        });

        onLoginSuccess();
      } else {
        // --- LOGIN ---
        await signInWithEmailAndPassword(auth, email, password);
        onLoginSuccess();
      }
    } catch (err: any) {
      console.error("Auth error:", err);
      let msg = "Authentication failed.";
      if (err.code === 'auth/invalid-credential') msg = "Invalid email or password.";
      if (err.code === 'auth/email-already-in-use') msg = "Email already registered.";
      if (err.code === 'auth/weak-password') msg = "Password should be at least 6 characters.";
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-950 p-4 relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-[#ff6b35]/5 rounded-full blur-3xl -z-10"></div>
      <div className="absolute bottom-1/4 right-1/4 w-64 h-64 bg-indigo-500/5 rounded-full blur-3xl -z-10"></div>

      <div className="max-w-md w-full bg-slate-900 border border-slate-800 rounded-2xl p-8 shadow-2xl">
        <div className="flex flex-col items-center mb-8">
          <div className="w-16 h-16 bg-[#ff6b35] rounded-2xl flex items-center justify-center mb-4 shadow-[0_0_20px_rgba(255,107,53,0.5)] transform rotate-3">
            <Sword className="w-8 h-8 text-white" />
          </div>
          <h1 className="text-3xl font-bold text-white tracking-tight">Level Up Life</h1>
          <p className="text-slate-400 mt-2">
            {isRegistering ? "Join the Guild" : "Welcome Back, Hero"}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          {error && (
            <div className="bg-red-500/10 border border-red-500/50 text-red-400 text-sm p-3 rounded-lg flex items-center gap-2">
              <AlertCircle className="w-4 h-4" />
              {error}
            </div>
          )}

          {isRegistering && (
            <div>
              <label className="block text-xs font-medium text-slate-400 mb-1 ml-1">
                Adventurer Name
              </label>
              <div className="relative">
                <UserIcon className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
                <input
                  type="text"
                  required
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  className="w-full bg-slate-950 border border-slate-800 rounded-lg py-3 pl-10 pr-4 text-white focus:ring-2 focus:ring-[#ff6b35] focus:border-[#ff6b35] transition-all outline-none"
                  placeholder="e.g. Sir CodeAlot"
                />
              </div>
            </div>
          )}

          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1 ml-1">
              Email Address
            </label>
            <div className="relative">
              <Mail className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
              <input
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-slate-950 border border-slate-800 rounded-lg py-3 pl-10 pr-4 text-white focus:ring-2 focus:ring-[#ff6b35] focus:border-[#ff6b35] transition-all outline-none"
                placeholder="hero@example.com"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1 ml-1">
              Password
            </label>
            <div className="relative">
              <Lock className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
              <input
                type="password"
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-slate-950 border border-slate-800 rounded-lg py-3 pl-10 pr-4 text-white focus:ring-2 focus:ring-[#ff6b35] focus:border-[#ff6b35] transition-all outline-none"
                placeholder="••••••••"
                minLength={6}
              />
            </div>
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-[#ff6b35] hover:bg-orange-500 text-white font-bold py-3 px-4 rounded-lg transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-[#ff6b35]/20 mt-6"
          >
            {loading ? (
              <span className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin" />
            ) : (
              isRegistering ? (
                <>
                  <UserPlus className="w-5 h-5" />
                  Create Account
                </>
              ) : (
                <>
                  <LogIn className="w-5 h-5" />
                  Enter World
                </>
              )
            )}
          </button>
        </form>

        <div className="mt-6 text-center">
          <button
            onClick={() => {
              setIsRegistering(!isRegistering);
              setError(null);
            }}
            className="text-slate-400 hover:text-[#ff6b35] text-sm transition-colors"
          >
            {isRegistering 
              ? "Already have an account? Sign In" 
              : "New here? Create an Account"}
          </button>
        </div>
      </div>
    </div>
  );
};

export type StatType = 'BODY' | 'MIND' | 'SOUL';
export type HabitType = 'good' | 'bad';

export const STAT_LABELS: Record<StatType, string> = {
  BODY: 'Body',
  MIND: 'Mind',
  SOUL: 'Soul',
};

export interface Habit {
  id: string;
  title: string;
  description?: string;
  type: HabitType;
  stat: StatType;
  xpReward: number;
  statReward: number;
  completedDates: string[]; // ISO date strings YYYY-MM-DD
  streak: number;
  createdAt: string;
}

export interface GratitudeEntry {
  id: string;
  date: string; // YYYY-MM-DD
  content: string;
  createdAt: string;
}

export interface UserStats {
  level: number;
  currentXp: number;
  nextLevelXp: number;
  attributes: Record<StatType, number>;
}

export interface User {
  id: string;
  email?: string | null;
  username: string;
  isLoggedIn: boolean;
}

export interface AppData {
  habits: Habit[];
  gratitudeLogs: GratitudeEntry[];
  stats: UserStats;
}

import React, { useState, useEffect } from 'react';
import { 
  Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer,
  Tooltip
} from 'recharts';
import { Plus, Check, Trash2, Trophy, Zap, Brain, Activity, Sword, Calendar, LogOut, Skull, AlertCircle, Heart, Send, ChevronDown, ChevronUp } from 'lucide-react';
import { format, isSameDay } from 'date-fns';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { Habit, UserStats, StatType, STAT_LABELS, User, HabitType, GratitudeEntry } from './types';
import { Login } from './components/Login';
import { ContributionGraph } from './components/ContributionGraph';
import { AvatarGenerator } from './components/AvatarGenerator';
import { ApiKeySelector } from './components/ApiKeySelector';
import { DB } from './services/db';
import { auth } from './services/firebaseConfig';

const STAT_ICONS: Record<StatType, React.ReactNode> = {
  BODY: <Activity className="w-4 h-4" />,
  MIND: <Brain className="w-4 h-4" />,
  SOUL: <Heart className="w-4 h-4" />,
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [gratitudeLogs, setGratitudeLogs] = useState<GratitudeEntry[]>([]);
  const [stats, setStats] = useState<UserStats>({
    level: 1, currentXp: 0, nextLevelXp: 100,
    attributes: { BODY: 1, MIND: 1, SOUL: 1 }
  });

  // UI State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [showGratitudeHistory, setShowGratitudeHistory] = useState(false);

  // Dashboard view state: 'positive' or 'negative'
  const [dashboardView, setDashboardView] = useState<'positive' | 'negative'>('positive');

  // Form State
  const [newHabitTitle, setNewHabitTitle] = useState('');
  const [newHabitStat, setNewHabitStat] = useState<StatType>('BODY');
  const [newHabitType, setNewHabitType] = useState<HabitType>('good');
  const [gratitudeInput, setGratitudeInput] = useState('');

  // 1. Auth Listener (Firebase)
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (authUser) => {
      if (authUser) {
        await initUser(authUser);
      } else {
        setUser(null);
        setHabits([]);
        setGratitudeLogs([]);
        setLoading(false);
      }
    });

    return () => unsubscribe();
  }, []);

  const initUser = async (authUser: any) => {
    const userData = await DB.getUserData(authUser.uid);

    // Fallback username if not found in table
    const username = authUser.displayName || (userData.habits.length > 0 ? 'Hero' : 'Adventurer');

    setHabits(userData.habits);
    setGratitudeLogs(userData.gratitudeLogs);
    setStats(userData.stats);

    setUser({
      id: authUser.uid,
      email: authUser.email,
      username: username,
      isLoggedIn: true
    });
    setLoading(false);
  };

  const handleLogout = async () => {
    await signOut(auth);
  };

  // 2. Auto-save to Firestore whenever data changes
  useEffect(() => {
    if (user && user.id && !loading) {
      const timer = setTimeout(() => {
        DB.saveUserData(user.id, user.username, { habits, gratitudeLogs, stats });
      }, 800); // Debounce save

      return () => clearTimeout(timer);
    }
  }, [habits, gratitudeLogs, stats, user, loading]);

  const addHabit = () => {
    if (!newHabitTitle.trim()) return;

    const newHabit: Habit = {
      id: crypto.randomUUID(),
      title: newHabitTitle,
      type: newHabitType,
      stat: newHabitStat,
      xpReward: 10,
      statReward: 1,
      completedDates: [],
      streak: 0,
      createdAt: new Date().toISOString()
    };

    setHabits([...habits, newHabit]);
    setNewHabitTitle('');
    setIsModalOpen(false);
  };

  const deleteHabit = (id: string) => {
    if (confirm('Are you sure you want to delete this habit? History will be kept but it will disappear from the list.')) {
       setHabits(habits.filter(h => h.id !== id));
    }
  };

  const updateStats = (xpChange: number, stat: StatType, statChange: number) => {
    setStats(prevStats => {
      let newXp = Math.max(0, prevStats.currentXp + xpChange);
      let newAttributes = { ...prevStats.attributes };
      newAttributes[stat] = Math.max(1, newAttributes[stat] + statChange);

      let newLevel = prevStats.level;
      let nextXp = prevStats.nextLevelXp;

      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }

      return {
        ...prevStats,
        level: newLevel,
        currentXp: newXp,
        nextLevelXp: nextXp,
        attributes: newAttributes
      };
    });
  };

  const toggleHabitCompletion = (id: string) => {
    const dateStr = format(selectedDate, 'yyyy-MM-dd');

    setHabits(prevHabits => {
      const habit = prevHabits.find(h => h.id === id);
      if (!habit) return prevHabits;

      const isCompleted = habit.completedDates.includes(dateStr);
      let newCompletedDates: string[];
      let xpChange = 0;
      let statChange = 0;

      const multiplier = habit.type === 'good' ? 1 : -1;

      if (isCompleted) {
        // Undoing
        newCompletedDates = habit.completedDates.filter(d => d !== dateStr);
        xpChange = -1 * habit.xpReward * multiplier;
        statChange = -1 * habit.statReward * multiplier;
      } else {
        // Doing
        newCompletedDates = [...habit.completedDates, dateStr];
        xpChange = habit.xpReward * multiplier;
        statChange = habit.statReward * multiplier;
      }

      updateStats(xpChange, habit.stat, statChange);

      return prevHabits.map(h => 
        h.id === id 
          ? { ...h, completedDates: newCompletedDates } 
          : h
      );
    });
  };

  const addGratitude = () => {
    if (!gratitudeInput.trim()) return;
    const dateStr = format(selectedDate, 'yyyy-MM-dd');

    const newEntry: GratitudeEntry = {
      id: crypto.randomUUID(),
      date: dateStr,
      content: gratitudeInput,
      createdAt: new Date().toISOString()
    };

    setGratitudeLogs(prev => [newEntry, ...prev]);
    setGratitudeInput('');
    // Reward for gratitude: XP +5, Soul +1
    updateStats(5, 'SOUL', 1);
  };

  const deleteGratitude = (id: string) => {
    if (confirm('Delete this gratitude entry? (Rewards will be deducted)')) {
      setGratitudeLogs(prev => prev.filter(g => g.id !== id));
      updateStats(-5, 'SOUL', -1);
    }
  };

  const openAddModal = (type: HabitType) => {
    setNewHabitType(type);
    setIsModalOpen(true);
  };

  if (loading) {
    return <div className="min-h-screen bg-slate-950 flex items-center justify-center text-slate-500 animate-pulse">Loading Realm...</div>;
  }

  if (!user) {
    // onLoginSuccess is handled by the auth state listener above
    return <Login onLoginSuccess={() => {}} />;
  }

  const radarData = Object.entries(stats.attributes).map(([key, value]) => ({
    subject: STAT_LABELS[key as StatType],
    A: value,
    fullMark: Math.max(...(Object.values(stats.attributes) as number[])) * 1.2
  }));

  const isSelectedToday = isSameDay(selectedDate, new Date());
  const dateStr = format(selectedDate, 'yyyy-MM-dd');

  const goodHabits = habits.filter(h => h.type === 'good');
  const badHabits = habits.filter(h => h.type === 'bad');
  const dailyGratitudes = gratitudeLogs.filter(g => g.date === dateStr);
  const historyGratitudes = gratitudeLogs.slice(0, 30); // Last 30 entries

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans pb-20">
      <ApiKeySelector onKeySelected={() => {}} /> 

      {/* Header */}
      <header className="bg-slate-900 border-b border-slate-800 sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-[#ff6b35] rounded flex items-center justify-center shadow-lg shadow-[#ff6b35]/20">
              <Trophy className="w-5 h-5 text-white" />
            </div>
            <span className="font-bold text-lg tracking-wide hidden sm:inline">Level Up Life</span>
          </div>

          <div className="flex items-center gap-4">
             <div className="text-sm text-slate-400 mr-2">
                Hello, <span className="text-white font-semibold">{user.username}</span>
             </div>
            <button 
              onClick={handleLogout}
              className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors flex items-center gap-2"
              title="Logout"
            >
              <span className="text-xs hidden md:inline">Logout</span>
              <LogOut className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 space-y-8">

        {/* Top Section: Character Stats Summary */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Level & XP Card - Square Layout */}
          <div className="aspect-square bg-slate-900 rounded-2xl border border-slate-800 p-8 shadow-xl relative overflow-hidden flex flex-col items-center justify-center text-center">
             {/* Background Decoration */}
             <div className="absolute top-0 right-0 w-64 h-64 bg-[#ff6b35]/5 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>

             <div className="flex items-center gap-2 mb-6">
                <Sword className="w-6 h-6 text-[#ff6b35]" />
                <h2 className="text-2xl font-bold text-white">Status</h2>
             </div>

             <div className="relative mb-8">
               <div className="w-32 h-32 bg-slate-950 rounded-full border-4 border-[#ff6b35]/30 flex items-center justify-center shadow-[0_0_30px_rgba(255,107,53,0.2)]">
                  <span className="text-6xl font-black text-white">{stats.level}</span>
               </div>
               <span className="absolute -bottom-3 left-1/2 -translate-x-1/2 bg-[#ff6b35] text-white text-xs font-bold px-3 py-1 rounded-full uppercase tracking-wider shadow-lg">Level</span>
             </div>

             <div className="w-full max-w-xs space-y-2">
               <div className="flex justify-between text-xs font-mono text-[#ff6b35]/80 uppercase tracking-wider">
                  <span>Experience</span>
                  <span>{stats.currentXp} / {stats.nextLevelXp}</span>
               </div>

               <div className="w-full h-4 bg-slate-950 rounded-full overflow-hidden border border-slate-700/50">
                  <div 
                    className="h-full bg-gradient-to-r from-[#ff6b35] to-orange-400 shadow-[0_0_15px_rgba(255,107,53,0.5)] transition-all duration-700 ease-out"
                    style={{ width: `${Math.min(100, (stats.currentXp / stats.nextLevelXp) * 100)}%` }}
                  />
               </div>
               <p className="text-slate-500 text-sm mt-4">Rank: {Math.floor(stats.level / 10) + 1} • {user.username}</p>
             </div>
          </div>

          {/* Attributes Radar (Square) */}
          <div className="aspect-square bg-slate-900 rounded-2xl border border-slate-800 p-4 shadow-xl flex flex-col justify-center items-center relative overflow-hidden">
             <div className="absolute top-6 left-6 flex items-center gap-2">
                <Activity className="w-5 h-5 text-[#ff6b35]" />
                <h3 className="text-lg font-bold text-slate-300">Attributes</h3>
             </div>

             <div className="w-full h-full p-4 mt-4">
                <ResponsiveContainer width="100%" height="100%">
                    <RadarChart cx="50%" cy="50%" outerRadius="70%" data={radarData}>
                    <PolarGrid stroke="#334155" />
                    <PolarAngleAxis dataKey="subject" tick={{ fill: '#94a3b8', fontSize: 14, fontWeight: 'bold' }} />
                    <PolarRadiusAxis angle={30} domain={[0, 'auto']} tick={false} axisLine={false} />
                    <Radar
                        name="Stats"
                        dataKey="A"
                        stroke="#ff6b35"
                        fill="#ff6b35"
                        fillOpacity={0.5}
                    />
                    <Tooltip 
                        contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f1f5f9', fontSize: '14px' }}
                        itemStyle={{ color: '#ff6b35' }}
                    />
                    </RadarChart>
                </ResponsiveContainer>
             </div>

             <div className="absolute bottom-6 w-full flex justify-center gap-6 text-sm font-mono text-slate-400">
                {Object.entries(stats.attributes).map(([k, v]) => (
                  <div key={k} className="flex flex-col items-center">
                    <span className="text-xs text-[#ff6b35] font-bold">{k}</span>
                    <span className="text-white font-bold text-lg">{v}</span>
                  </div>
                ))}
             </div>
          </div>
        </div>

        {/* Avatar Generator Section */}
        <AvatarGenerator stats={stats} />

        {/* Middle Section: Dashboard */}
        <div className="bg-slate-900 rounded-2xl border border-slate-800 p-8 shadow-xl">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-bold flex items-center gap-2 text-white">
                <Calendar className="w-6 h-6 text-[#ff6b35]" />
                Activity Log
              </h2>

              <div className="flex gap-2 p-1 bg-slate-950 rounded-lg border border-slate-800">
                <button
                  onClick={() => setDashboardView('positive')}
                  className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${
                    dashboardView === 'positive' 
                      ? 'bg-[#ff6b35] text-white shadow shadow-orange-500/20' 
                      : 'text-slate-500 hover:text-slate-300'
