import { doc, getDoc, setDoc } from 'firebase/firestore';
import { db } from './firebase';
import { AppData, UserStats } from '../types';

const INITIAL_STATS: UserStats = {
  level: 1,
  currentXp: 0,
  nextLevelXp: 100,
  attributes: {
    BODY: 1,
    MIND: 1,
    SOUL: 1,
  },
};

const INITIAL_DATA: AppData = {
  habits: [],
  gratitudeLogs: [],
  stats: INITIAL_STATS,
};

export class FirestoreDB {
  /**
   * Fetches user data from Firestore.
   * If the document does not exist (new user), it creates it with initial data.
   */
  static async fetchUserDocument(uid: string): Promise<AppData> {
    try {
      const userDocRef = doc(db, 'users', uid);
      const userSnap = await getDoc(userDocRef);

      if (userSnap.exists()) {
        return userSnap.data() as AppData;
      } else {
        // Doc doesn't exist, create it automatically
        await setDoc(userDocRef, INITIAL_DATA);
        return INITIAL_DATA;
      }
    } catch (error) {
      console.error("Error fetching user data:", error);
      throw error;
    }
  }

  /**
   * Updates the user's document in Firestore.
   * Uses setDoc with { merge: true } to be safe against schema changes.
   */
  static async updateUserDocument(uid: string, data: AppData): Promise<void> {
    try {
      const userDocRef = doc(db, 'users', uid);
      await setDoc(userDocRef, data, { merge: true });
    } catch (error) {
      console.error("Error updating user data:", error);
      throw error;
    }
  }
}

