    level: 1, currentXp: 0, nextLevelXp: 100,
    attributes: { BODY: 1, MIND: 1, SOUL: 1 }
  });

  // Data Loading State
  const [isDataLoaded, setIsDataLoaded] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  // UI State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());

  // View States
  const [dashboardView, setDashboardView] = useState<'positive' | 'negative'>('positive');
  const [chartMode, setChartMode] = useState<'monthly' | 'weekly'>('monthly');

  // Form State
  const [newHabitTitle, setNewHabitTitle] = useState('');
  const [newHabitStat, setNewHabitStat] = useState<StatType>('BODY');
  const [newHabitType, setNewHabitType] = useState<HabitType>('good');

  // Test Function
  const handleTestConnection = async () => {
    if (!firebaseUid) return;
    try {
      const testRef = doc(db, 'test_connection', firebaseUid);
      await setDoc(testRef, {
        message: "Hello from the Realm!",
        timestamp: new Date().toISOString(),
        user: user?.username
      });
      alert("✅ Success! Firestore is connected. Check your Firebase Console 'test_connection' collection.");
    } catch (error: any) {
      console.error(error);
      alert(`❌ Connection Failed: ${error.message}`);
    }
  };

  // Firebase Auth Listener & Data Fetching
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        const uid = firebaseUser.uid;
        const displayName = firebaseUser.displayName || firebaseUser.email?.split('@')[0] || 'Adventurer';

        setFirebaseUid(uid);
        setUser({ username: displayName, isLoggedIn: true });

        try {
          const data = await FirestoreDB.fetchUserDocument(uid);

          const migratedHabits = data.habits ? data.habits.map(h => ({ ...h, type: h.type || 'good' })) : [];
          setHabits(migratedHabits);
          setGratitudeLogs(data.gratitudeLogs || []);
          setStats(data.stats || {
            level: 1, currentXp: 0, nextLevelXp: 100,
            attributes: { BODY: 1, MIND: 1, SOUL: 1 }
          });

          setIsDataLoaded(true); 
        } catch (error) {
          console.error("Failed to load user data:", error);
          // Don't block UI on error, just log it
        }
      } else {
        setUser(null);
        setFirebaseUid(null);
        setHabits([]);
        setGratitudeLogs([]);
        setStats({
          level: 1, currentXp: 0, nextLevelXp: 100,
          attributes: { BODY: 1, MIND: 1, SOUL: 1 }
        });
        setIsDataLoaded(false);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleLogout = async () => {
    try {
      await signOut(auth);
    } catch (error) {
      console.error("Error signing out:", error);
    }
  };

  // Auto-save
  useEffect(() => {
    const saveData = async () => {
      if (firebaseUid && isDataLoaded) {
        setIsSaving(true);
        try {
          await FirestoreDB.updateUserDocument(firebaseUid, { habits, gratitudeLogs, stats });
        } catch (error) {
          console.error("Error saving data:", error);
        } finally {
          setIsSaving(false);
        }
      }
    };

    const timeoutId = setTimeout(saveData, 1000);
    return () => clearTimeout(timeoutId);
  }, [habits, gratitudeLogs, stats, firebaseUid, isDataLoaded]);

