    if (!newHabitTitle.trim()) return;

    const newHabit: Habit = {
      id: crypto.randomUUID(),
      title: newHabitTitle,
      type: newHabitType,
      stat: newHabitStat,
      xpReward: 10,
      statReward: 1,
      completedDates: [],
