function renderHeatmap() {
    const grid = document.getElementById('heatmap-grid');
    const monthLabel = document.getElementById('heatmap-month-label');

    const viewDate = state.ui.viewDate;
    monthLabel.innerText = dateFns.format(viewDate, 'MMMM yyyy');

    const monthStart = dateFns.startOfMonth(viewDate);
    const monthEnd = dateFns.endOfMonth(viewDate);
    const start = dateFns.startOfWeek(monthStart);
    const end = dateFns.endOfWeek(monthEnd);

    const days = dateFns.eachDayOfInterval({ start, end });

    // Group by week
    const weeks = [];
    let currentWeek = [];
    days.forEach(day => {
        currentWeek.push(day);
        if (currentWeek.length === 7) {
            weeks.push(currentWeek);
            currentWeek = [];
        }
    });

    const isPositive = state.ui.dashboardView === 'positive';
    const activeColor = isPositive ? 'bg-[#ff6b35]' : 'bg-rose-500';
    const activeHabits = state.habits.filter(h => h.type === (isPositive ? 'good' : 'bad'));

    let html = '';
    weeks.forEach(week => {
        html += '<div class="flex flex-col gap-2">';
        week.forEach(day => {
            const dateStr = dateFns.format(day, 'yyyy-MM-dd');
            const isToday = dateFns.isSameDay(day, new Date());
            const isSelected = dateFns.isSameDay(day, state.ui.selectedDate);
            const inMonth = dateFns.isSameMonth(day, viewDate);

            // Calc score
            let count = 0;
            activeHabits.forEach(h => { if(h.completedDates.includes(dateStr)) count++; });
            if(isPositive) {
                count += state.gratitudeLogs.filter(g => g.date === dateStr).length;
            }

            // Style
            let colorClass = 'bg-slate-800/50';
            if (count > 0) colorClass = isPositive 
                ? (count > 2 ? 'bg-[#ff6b35]' : count > 1 ? 'bg-[#ff6b35]/60' : 'bg-[#ff6b35]/30') 
                : (count > 2 ? 'bg-rose-500' : count > 1 ? 'bg-rose-700' : 'bg-rose-900');

            const opacity = inMonth ? 'opacity-100' : 'opacity-20 grayscale';
            const border = isSelected ? 'ring-2 ring-white scale-110 z-10' : (isToday ? 'border border-[#ff6b35]/80' : 'border border-transparent');

            html += `
                <div onclick="window.selectDate('${dateStr}')" 
                     class="w-10 h-10 rounded-lg cursor-pointer transition-all flex items-center justify-center ${colorClass} ${opacity} ${border}">
                     <span class="text-xs ${count > 0 ? 'text-white' : 'text-slate-600'}">${dateFns.format(day, 'd')}</span>
                </div>
            `;
        });
        html += '</div>';
    });
    grid.innerHTML = html;
}

function renderGratitude() {
    const dateStr = dateFns.format(state.ui.selectedDate, 'yyyy-MM-dd');
    const container = document.getElementById('gratitude-list');
    const historyContainer = document.getElementById('gratitude-history');

    // Daily Logs
    const daily = state.gratitudeLogs.filter(g => g.date === dateStr);
