// --- Auth & Startup Logic ---
function setupAuthLogic() {
    setupLoginForm();
    document.getElementById('btn-logout')?.addEventListener('click', handleLogout);

    // CRITICAL FIX: Safety Timeout
    // If Firebase is stuck (common on file:// or bad network), force show Login after 2.5s
    const authTimeout = setTimeout(() => {
        if (!state.user && !screens.dashboard.classList.contains('hidden')) return; // Already loaded

        console.warn("Auth check timed out. Forcing UI load.");
        if (screens.loading && !screens.loading.classList.contains('hidden')) {
            screens.loading.classList.add('hidden');
            screens.login.classList.remove('hidden');

            const errorEl = document.getElementById('error-message');
            if(errorEl) {
                errorEl.innerText = "Connection slow. Please try logging in.";
                errorEl.classList.remove('hidden');
            }
        }
    }, 2500);

    if (!isOfflineMode && auth) {
        auth.onAuthStateChanged(async (user) => {
            clearTimeout(authTimeout); // Cancel the safety timer

            screens.loading.classList.remove('hidden'); // Show loading briefly while fetching data

            if (user) {
                state.user = user;
                updateUserDisplay(user);
                await loadUserData(user.uid);
                showScreen('dashboard');
            } else {
                state.user = null;
                showScreen('login');
            }
        }, (error) => {
            clearTimeout(authTimeout);
            console.error("Auth Observer Error", error);
            showScreen('login');
        });
    } else {
        // Offline Mode Immediate Load
        clearTimeout(authTimeout);
        console.log("Running in Offline Mode");
        showScreen('login');
        const subtitle = document.getElementById('auth-subtitle');
        if(subtitle) subtitle.innerText = "Offline Mode (Data saves to browser)";
    }
}

function showScreen(screenName) {
    if(screens.loading) screens.loading.classList.add('hidden');
    if(screens.login) screens.login.classList.add('hidden');
    if(screens.dashboard) screens.dashboard.classList.add('hidden');

    if (screenName === 'loading') screens.loading.classList.remove('hidden');
    if (screenName === 'login') screens.login.classList.remove('hidden');
    if (screenName === 'dashboard') screens.dashboard.classList.remove('hidden');
}

function setupLoginForm() {
    const form = document.getElementById('auth-form');
    const toggleBtn = document.getElementById('btn-toggle-auth-mode');
    const usernameField = document.getElementById('username-field');
    const title = document.getElementById('auth-subtitle');
    const submitBtnText = document.getElementById('btn-auth-text');
    let isRegistering = false;

    if(toggleBtn) {
        toggleBtn.addEventListener('click', () => {
            isRegistering = !isRegistering;
            usernameField.classList.toggle('hidden', !isRegistering);
            title.innerText = isRegistering ? "Begin Your Journey" : "Continue Your Adventure";
            submitBtnText.innerText = isRegistering ? "Create Account" : "Enter Realm";
            toggleBtn.innerText = isRegistering ? "Already have an account? Login" : "New to the realm? Create Account";
            document.getElementById('input-username').required = isRegistering;
        });
    }

    if(form) {
        form.onsubmit = (e) => e.preventDefault();
        form.addEventListener('submit', async (e) => {
            e.preventDefault();
            const email = document.getElementById('input-email').value;
            const password = document.getElementById('input-password').value;
            const username = document.getElementById('input-username').value;
            const errorDiv = document.getElementById('auth-error');

            if(errorDiv) errorDiv.classList.add('hidden');

            try {
                if (isOfflineMode) {
                    // Mock Login for Offline Mode
                    state.user = { uid: "offline_user", email: email, displayName: username || "Offline Hero" };
                    updateUserDisplay(state.user);
                    await loadUserData(state.user.uid);
                    showScreen('dashboard');
                    return;
                }

                if (isRegistering) {
                    const userCredential = await auth.createUserWithEmailAndPassword(email, password);
                    if (userCredential.user) {
                        await userCredential.user.updateProfile({ displayName: username });
                    }
                } else {
                    await auth.signInWithEmailAndPassword(email, password);
                }
            } catch (err) {
                console.error(err);
                if(errorDiv) {
                    errorDiv.classList.remove('hidden');
                    document.getElementById('auth-error-text').innerText = err.message.replace('Firebase:', '').trim();
                }
            }
        });
    }
}

function handleLogout() {
    if (isOfflineMode) {
        state.user = null;
        showScreen('login');
    } else {
        auth.signOut();
    }
}

function updateUserDisplay(user) {
    const displayName = user.displayName || user.email.split('@')[0];
    const displayEl = document.getElementById('user-display-name');
    if(displayEl) displayEl.innerText = displayName;
}

// --- Data Logic (DB & Migration) ---
async function loadUserData(uid) {
    // 1. Try to load from LocalStorage first (for offline or migration)
    const localDataJSON = localStorage.getItem(LOCAL_STORAGE_KEY);
    let localData = null;
    if (localDataJSON) {
        try { localData = JSON.parse(localDataJSON); } catch (e) { console.error("Parse Error", e); }
    }

    if (isOfflineMode) {
        if (localData) {
            state.habits = localData.habits || [];
            state.gratitudeLogs = localData.gratitudeLogs || [];
            state.stats = localData.stats || INITIAL_STATS;
        }
        renderAll();
        return;
    }

    // 2. Try Firebase
    try {
        const docRef = db.collection('users').doc(uid);
        const docSnap = await docRef.get();
        let data;

        if (docSnap.exists) {
            data = docSnap.data();
        } else {
            data = { habits: [], gratitudeLogs: [], stats: INITIAL_STATS };
            // If we have local data but cloud is empty, migrate
            if (localData && (!data.habits || data.habits.length === 0)) {
                data = {
                    habits: localData.habits || [],
                    gratitudeLogs: localData.gratitudeLogs || [],
                    stats: localData.stats || INITIAL_STATS
                };
            }
            await docRef.set(data, { merge: true });
        }

        state.habits = (data.habits || []).map(h => ({...h, type: h.type || 'good'}));
        state.gratitudeLogs = data.gratitudeLogs || [];
        state.stats = data.stats || INITIAL_STATS;

    } catch (e) {
        console.error("Cloud Load Error:", e);
        // Fallback to local if cloud fails
        if (localData) {
            state.habits = localData.habits || [];
            state.gratitudeLogs = localData.gratitudeLogs || [];
            state.stats = localData.stats || INITIAL_STATS;
        }
        document.getElementById('saving-indicator').innerText = "Offline Mode";
    }

    renderAll();
}

async function saveData() {
    const dataToSave = {
        habits: state.habits,
        gratitudeLogs: state.gratitudeLogs,
        stats: state.stats
    };

    // Always save to local storage as backup/offline
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(dataToSave));

    if (isOfflineMode || !state.user || state.user.uid === 'offline_user') return;

    const indicator = document.getElementById('saving-indicator');
    if(indicator) {
        indicator.classList.remove('hidden');
        indicator.innerHTML = '<i data-lucide="loader-2" class="w-3 h-3 animate-spin"></i> Saving...';
        safeCreateIcons();
    }

    try {
        await db.collection('users').doc(state.user.uid).set(dataToSave, { merge: true });
    } catch (e) {
        console.error("Save failed", e);
        if(indicator) indicator.innerText = "Save Failed (Offline)";
    } finally {
        setTimeout(() => indicator && indicator.classList.add('hidden'), 500);
    }
}

// --- Game Logic ---
function updateStats(xpChange, statKey, statChange) {
    let { level, currentXp, nextLevelXp, attributes } = state.stats;

    currentXp = Math.max(0, currentXp + xpChange);
    attributes[statKey] = Math.max(1, attributes[statKey] + statChange);

    while (currentXp >= nextLevelXp) {
        currentXp -= nextLevelXp;
        level += 1;
        nextLevelXp = Math.floor(nextLevelXp * 1.2);
    }

    state.stats = { level, currentXp, nextLevelXp, attributes };
    renderStats();
    saveData();
}

// --- UI Rendering ---
function renderAll() {
    try {
        renderStats();
        renderDate();
        renderHabits();
