function setupDashboardListeners() {
    document.getElementById('btn-save-habit')?.addEventListener('click', () => {
        const title = document.getElementById('modal-habit-title').value;
        if (!title.trim()) return;

        const newHabit = {
            id: crypto.randomUUID(),
            title,
            type: state.ui.modalType,
            stat: state.ui.selectedStat,
            xpReward: 10,
            statReward: 1,
            completedDates: [],
            streak: 0,
            createdAt: new Date().toISOString()
        };

        state.habits.push(newHabit);
        saveData();
        renderHabits();
        renderHeatmap();
        closeModal();
    });

    document.getElementById('btn-add-gratitude')?.addEventListener('click', addGratitude);
    document.getElementById('gratitude-input')?.addEventListener('keydown', (e) => e.key === 'Enter' && addGratitude());

    document.getElementById('btn-prev-month')?.addEventListener('click', () => {
        if(window.dateFns) {
            state.ui.viewDate = dateFns.addMonths(state.ui.viewDate, -1);
            renderHeatmap();
        }
    });
    document.getElementById('btn-next-month')?.addEventListener('click', () => {
        if(window.dateFns) {
            state.ui.viewDate = dateFns.addMonths(state.ui.viewDate, 1);
            renderHeatmap();
        }
    });
}

window.selectDate = (dateStr) => {
    state.ui.selectedDate = new Date(dateStr);
    renderAll();
};

window.setDashboardView = (view) => {
    state.ui.dashboardView = view;
    document.getElementById('btn-view-positive').className = view === 'positive' 
        ? "px-3 py-1.5 rounded-md text-xs font-bold transition-all bg-[#ff6b35] text-white shadow"
        : "px-3 py-1.5 rounded-md text-xs font-bold transition-all text-slate-500 hover:text-slate-300";
    document.getElementById('btn-view-negative').className = view === 'negative'
        ? "px-3 py-1.5 rounded-md text-xs font-bold transition-all bg-rose-600 text-white shadow"
        : "px-3 py-1.5 rounded-md text-xs font-bold transition-all text-slate-500 hover:text-slate-300";
    renderHeatmap();
};

window.toggleHabit = (id) => {
    if(!window.dateFns) return;
    const habit = state.habits.find(h => h.id === id);
    if (!habit) return;

    const dateStr = dateFns.format(state.ui.selectedDate, 'yyyy-MM-dd');
    const isCompleted = habit.completedDates.includes(dateStr);
    const mult = habit.type === 'good' ? 1 : -1;

    if (isCompleted) {
        habit.completedDates = habit.completedDates.filter(d => d !== dateStr);
        updateStats(-10 * mult, habit.stat, -1 * mult);
    } else {
        habit.completedDates.push(dateStr);
        updateStats(10 * mult, habit.stat, 1 * mult);
    }
    renderHabits();
    renderHeatmap();
    saveData();
};

window.deleteHabit = (id) => {
    if (confirm("Delete this habit?")) {
        state.habits = state.habits.filter(h => h.id !== id);
        renderHabits();
        renderHeatmap();
        saveData();
    }
};

window.deleteGratitude = (id) => {
    if(confirm("Remove entry?")) {
        state.gratitudeLogs = state.gratitudeLogs.filter(g => g.id !== id);
        updateStats(-5, 'SOUL', -1);
        renderGratitude();
        renderHeatmap();
        saveData();
    }
};

function addGratitude() {
    if(!window.dateFns) return;
    const input = document.getElementById('gratitude-input');
    const val = input.value.trim();
    if (!val) return;

    state.gratitudeLogs.unshift({
        id: crypto.randomUUID(),
        date: dateFns.format(state.ui.selectedDate, 'yyyy-MM-dd'),
        content: val,
        createdAt: new Date().toISOString()
    });

    updateStats(5, 'SOUL', 1);
    input.value = '';
    renderGratitude();
    renderHeatmap();
    saveData();
}

window.toggleGratitudeHistory = () => {
    document.getElementById('gratitude-history').classList.toggle('hidden');
};

window.openModal = (type) => {
    state.ui.modalType = type;
    const modal = document.getElementById('habit-modal');
