        <div class="flex flex-col items-center">
            <span class="text-xs text-[#ff6b35] font-bold">${k}</span>
            <span class="text-white font-bold text-lg">${v}</span>
        </div>
    `).join('');

    const ctx = document.getElementById('radarChart');
    if (radarChartInstance) radarChartInstance.destroy();

    if (typeof Chart !== 'undefined') {
        radarChartInstance = new Chart(ctx, {
            type: 'radar',
            data: {
                labels: ['Body', 'Mind', 'Soul'],
                datasets: [{
                    label: 'Stats',
                    data: [attributes.BODY, attributes.MIND, attributes.SOUL],
                    backgroundColor: 'rgba(255, 107, 53, 0.5)',
                    borderColor: '#ff6b35',
                    borderWidth: 2,
                    pointBackgroundColor: '#fff'
                }]
            },
            options: {
                scales: {
                    r: {
                        angleLines: { color: '#334155' },
                        grid: { color: '#334155' },
                        pointLabels: { color: '#94a3b8', font: { size: 14, weight: 'bold' } },
                        ticks: { display: false, backdropColor: 'transparent' },
                        suggestedMin: 0
                    }
                },
                plugins: { legend: { display: false } },
                maintainAspectRatio: false
            }
        });
    }
}

function renderAnalytics() {
    if (typeof Chart === 'undefined' || !window.dateFns) return;

    const ctx = document.getElementById('analyticsChart');
    if (analyticsChartInstance) analyticsChartInstance.destroy();

    const isWeek = state.ui.chartMode === 'week';
    const endDate = new Date();
    const startDate = isWeek ? dateFns.subDays(endDate, 6) : dateFns.subDays(endDate, 29);
    const interval = { start: startDate, end: endDate };
    const days = dateFns.eachDayOfInterval(interval);

    const labels = days.map(d => dateFns.format(d, isWeek ? 'EEE' : 'MMM d'));

    // Aggregate completed habits per day
    const dataPoints = days.map(day => {
        const dateStr = dateFns.format(day, 'yyyy-MM-dd');
        // Count all good habits completed on this date
        const goodHabitsDone = state.habits.filter(h => h.type === 'good' && h.completedDates.includes(dateStr)).length;
        // Subtract bad habits? Or just count activity? Let's just count Good Habits for "Performance"
        return goodHabitsDone;
    });

    analyticsChartInstance = new Chart(ctx, {
        type: isWeek ? 'bar' : 'line',
        data: {
            labels: labels,
            datasets: [{
                label: 'Completed Good Habits',
                data: dataPoints,
                backgroundColor: isWeek ? '#ff6b35' : 'rgba(255, 107, 53, 0.2)',
                borderColor: '#ff6b35',
                borderWidth: 2,
                borderRadius: 4,
                tension: 0.4,
                fill: !isWeek
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            scales: {
                y: {
                    beginAtZero: true,
                    grid: { color: '#334155' },
                    ticks: { color: '#94a3b8', stepSize: 1 }
                },
                x: {
                    grid: { display: false },
                    ticks: { color: '#94a3b8' }
                }
            },
            plugins: {
                legend: { display: false }
            }
        }
    });

    // Update buttons
    document.getElementById('btn-chart-week').className = isWeek 
        ? "px-3 py-1 text-xs font-bold rounded bg-[#ff6b35] text-white transition-all"
        : "px-3 py-1 text-xs font-bold rounded text-slate-400 hover:text-white transition-all";
    document.getElementById('btn-chart-month').className = !isWeek
        ? "px-3 py-1 text-xs font-bold rounded bg-[#ff6b35] text-white transition-all"
        : "px-3 py-1 text-xs font-bold rounded text-slate-400 hover:text-white transition-all";
}

function renderHabits() {
    if(!window.dateFns) return;
    const dateStr = dateFns.format(state.ui.selectedDate, 'yyyy-MM-dd');
    const goodList = document.getElementById('good-habits-list');
    const badList = document.getElementById('bad-habits-list');

    goodList.innerHTML = '';
    badList.innerHTML = '';

    const createHabitHTML = (habit) => {
        const isGood = habit.type === 'good';
        const isCompleted = habit.completedDates.includes(dateStr);
        const color = isGood ? '#ff6b35' : '#e11d48'; 
        const bgClass = isCompleted 
            ? (isGood ? 'bg-[#ff6b35]/20 border-[#ff6b35]/50' : 'bg-rose-950/20 border-rose-900/50') 
            : 'bg-slate-950 border-slate-800';

        const btnClass = isCompleted 
            ? (isGood ? 'bg-[#ff6b35] text-white scale-110' : 'bg-rose-500 text-white scale-110') 
            : 'bg-slate-800 text-slate-600 hover:bg-slate-700';

        return `
        <div class="flex items-center justify-between p-4 rounded-xl border transition-all ${bgClass} fade-in">
            <div class="flex items-center gap-4 flex-1">
                <button onclick="window.toggleHabit('${habit.id}')" class="w-12 h-12 rounded-xl flex items-center justify-center transition-all ${btnClass}">
                    <i data-lucide="${isGood ? 'check' : 'alert-circle'}" class="w-6 h-6"></i>
                </button>
                <div>
                    <h3 class="font-semibold text-lg ${isCompleted ? 'text-slate-400' : 'text-slate-100'}">${habit.title}</h3>
                    <div class="flex gap-2 text-xs text-slate-500 items-center mt-1">
                        <span class="bg-slate-900 px-2 py-0.5 rounded font-bold flex items-center gap-1 text-[${color}]">
                            ${STAT_ICONS[habit.stat]} ${habit.stat} ${isGood ? '+' : '-'}${habit.statReward}
                        </span>
                        <span class="bg-slate-900 px-2 py-0.5 rounded font-bold ${isGood ? 'text-indigo-300' : 'text-rose-400'}">
                            XP ${isGood ? '+' : '-'}${habit.xpReward}
                        </span>
                    </div>
                </div>
            </div>
            <button onclick="window.deleteHabit('${habit.id}')" class="text-slate-600 hover:text-red-400 p-2">
                <i data-lucide="trash-2" class="w-5 h-5"></i>
            </button>
        </div>
        `;
    };

    state.habits.filter(h => h.type === 'good').forEach(h => goodList.innerHTML += createHabitHTML(h));
    state.habits.filter(h => h.type === 'bad').forEach(h => badList.innerHTML += createHabitHTML(h));

    if(goodList.innerHTML === '') goodList.innerHTML = '<p class="text-slate-500 text-center text-sm">No good habits yet.</p>';
    if(badList.innerHTML === '') badList.innerHTML = '<p class="text-slate-500 text-center text-sm">No bad habits yet.</p>';
}

function renderHeatmap() {
    if(!window.dateFns) return;
    const grid = document.getElementById('heatmap-grid');
    const monthLabel = document.getElementById('heatmap-month-label');
    const viewDate = state.ui.viewDate;
    monthLabel.innerText = dateFns.format(viewDate, 'MMMM yyyy');

    const monthStart = dateFns.startOfMonth(viewDate);
    const monthEnd = dateFns.endOfMonth(viewDate);
    const start = dateFns.startOfWeek(monthStart);
    const end = dateFns.endOfWeek(monthEnd);
    const days = dateFns.eachDayOfInterval({ start, end });

    const weeks = [];
    let currentWeek = [];
    days.forEach(day => {
        currentWeek.push(day);
        if (currentWeek.length === 7) { weeks.push(currentWeek); currentWeek = []; }
    });

    const isPositive = state.ui.dashboardView === 'positive';
    const activeHabits = state.habits.filter(h => h.type === (isPositive ? 'good' : 'bad'));

    let html = '';
    weeks.forEach(week => {
        html += '<div class="flex flex-col gap-2">';
        week.forEach(day => {
            const dateStr = dateFns.format(day, 'yyyy-MM-dd');
            const isToday = dateFns.isSameDay(day, new Date());
            const isSelected = dateFns.isSameDay(day, state.ui.selectedDate);
            const inMonth = dateFns.isSameMonth(day, viewDate);

            let count = 0;
            activeHabits.forEach(h => { if(h.completedDates.includes(dateStr)) count++; });
            if(isPositive) count += state.gratitudeLogs.filter(g => g.date === dateStr).length;

            let colorClass = 'bg-slate-800/50';
            if (count > 0) colorClass = isPositive 
                ? (count > 2 ? 'bg-[#ff6b35]' : count > 1 ? 'bg-[#ff6b35]/60' : 'bg-[#ff6b35]/30') 
                : (count > 2 ? 'bg-rose-500' : count > 1 ? 'bg-rose-700' : 'bg-rose-900');

            const opacity = inMonth ? 'opacity-100' : 'opacity-20 grayscale';
            const border = isSelected ? 'ring-2 ring-white scale-110 z-10' : (isToday ? 'border border-[#ff6b35]/80' : 'border border-transparent');

            html += `<div onclick="window.selectDate('${dateStr}')" 
                     class="w-10 h-10 rounded-lg cursor-pointer transition-all flex items-center justify-center ${colorClass} ${opacity} ${border}">
                     <span class="text-xs ${count > 0 ? 'text-white' : 'text-slate-600'}">${dateFns.format(day, 'd')}</span>
                </div>`;
        });
        html += '</div>';
    });
    grid.innerHTML = html;
}

function renderGratitude() {
    if(!window.dateFns) return;
    const dateStr = dateFns.format(state.ui.selectedDate, 'yyyy-MM-dd');
    const container = document.getElementById('gratitude-list');
    const historyContainer = document.getElementById('gratitude-history');

    const daily = state.gratitudeLogs.filter(g => g.date === dateStr);
    container.innerHTML = daily.map(entry => `
        <div class="bg-amber-950/20 border border-amber-900/30 p-4 rounded-lg mb-3 flex justify-between items-start fade-in">
            <p class="text-amber-100">${entry.content}</p>
            <button onclick="window.deleteGratitude('${entry.id}')" class="text-slate-600 hover:text-amber-500 p-1"><i data-lucide="trash-2" class="w-4 h-4"></i></button>
        </div>
    `).join('') || '<p class="text-slate-500 text-sm italic">No entries for this day.</p>';

    historyContainer.innerHTML = state.gratitudeLogs.slice(0, 30).map(entry => `
        <div class="text-sm border-b border-slate-800/50 pb-2 mb-2">
            <div class="text-slate-500 text-xs mb-1 flex justify-between">
                <span>${entry.date}</span>
                <button onclick="window.deleteGratitude('${entry.id}')" class="hover:text-red-400"><i data-lucide="trash-2" class="w-3 h-3"></i></button>
            </div>
            <p class="text-slate-300">${entry.content}</p>
        </div>
    `).join('');
}

// --- Global Functions ---
function setupDashboardListeners() {
    document.getElementById('btn-save-habit')?.addEventListener('click', () => {
        const title = document.getElementById('modal-habit-title').value;
        if (!title.trim()) return;

        const newHabit = {
            id: crypto.randomUUID(),
            title,
            type: state.ui.modalType,
            stat: state.ui.selectedStat,
            xpReward: 10,
            statReward: 1,
            completedDates: [],
            streak: 0,
            createdAt: new Date().toISOString()
        };

        state.habits.push(newHabit);
        saveData();
        renderAll();
        closeModal();
    });

    document.getElementById('btn-add-gratitude')?.addEventListener('click', addGratitude);
    document.getElementById('gratitude-input')?.addEventListener('keydown', (e) => e.key === 'Enter' && addGratitude());
    document.getElementById('btn-prev-month')?.addEventListener('click', () => {
        if(window.dateFns) { state.ui.viewDate = dateFns.addMonths(state.ui.viewDate, -1); renderHeatmap(); }
    });
    document.getElementById('btn-next-month')?.addEventListener('click', () => {
        if(window.dateFns) { state.ui.viewDate = dateFns.addMonths(state.ui.viewDate, 1); renderHeatmap(); }
    });
}

window.selectDate = (dateStr) => { state.ui.selectedDate = new Date(dateStr); renderAll(); };
window.switchChart = (mode) => { state.ui.chartMode = mode; renderAnalytics(); };
window.setDashboardView = (view) => {
    state.ui.dashboardView = view;
    document.getElementById('btn-view-positive').className = view === 'positive' ? "px-3 py-1.5 rounded-md text-xs font-bold transition-all bg-[#ff6b35] text-white shadow" : "px-3 py-1.5 rounded-md text-xs font-bold transition-all text-slate-500 hover:text-slate-300";
    document.getElementById('btn-view-negative').className = view === 'negative' ? "px-3 py-1.5 rounded-md text-xs font-bold transition-all bg-rose-600 text-white shadow" : "px-3 py-1.5 rounded-md text-xs font-bold transition-all text-slate-500 hover:text-slate-300";
    renderHeatmap();
};

window.toggleHabit = (id) => {
    if(!window.dateFns) return;
    const habit = state.habits.find(h => h.id === id);
    if (!habit) return;

    const dateStr = dateFns.format(state.ui.selectedDate, 'yyyy-MM-dd');
    const isCompleted = habit.completedDates.includes(dateStr);
    const mult = habit.type === 'good' ? 1 : -1;

    if (isCompleted) {
        habit.completedDates = habit.completedDates.filter(d => d !== dateStr);
        updateStats(-10 * mult, habit.stat, -1 * mult);
    } else {
        habit.completedDates.push(dateStr);
        updateStats(10 * mult, habit.stat, 1 * mult);
    }
    renderAll();
    saveData();
};

window.deleteHabit = (id) => {
    if (confirm("Delete this habit?")) {
        state.habits = state.habits.filter(h => h.id !== id);
        renderAll();
        saveData();
    }
};

window.deleteGratitude = (id) => {
    if(confirm("Remove entry?")) {
        state.gratitudeLogs = state.gratitudeLogs.filter(g => g.id !== id);
        updateStats(-5, 'SOUL', -1);
        renderAll();
        saveData();
    }
};

function addGratitude() {
    if(!window.dateFns) return;
    const input = document.getElementById('gratitude-input');
    const val = input.value.trim();
    if (!val) return;

    state.gratitudeLogs.unshift({ id: crypto.randomUUID(), date: dateFns.format(state.ui.selectedDate, 'yyyy-MM-dd'), content: val, createdAt: new Date().toISOString() });
    updateStats(5, 'SOUL', 1);
    input.value = '';
    renderAll();
    saveData();
}

window.toggleGratitudeHistory = () => document.getElementById('gratitude-history').classList.toggle('hidden');

window.openModal = (type) => {
    state.ui.modalType = type;
    const modal = document.getElementById('habit-modal');
    document.getElementById('modal-title').innerText = `Add ${type === 'good' ? 'Good' : 'Bad'} Habit`;
    document.getElementById('modal-habit-title').value = '';
    document.getElementById('modal-habit-title').focus();
    document.getElementById('modal-stat-selector').innerHTML = Object.entries({BODY: 'Body', MIND: 'Mind', SOUL: 'Soul'}).map(([key, label]) => `
        <button onclick="window.selectStat('${key}')" class="stat-btn p-2 text-sm rounded-lg border flex flex-col items-center gap-1 transition-all ${state.ui.selectedStat === key ? 'bg-[#ff6b35] border-[#ff6b35] text-white' : 'bg-slate-950 border-slate-700 text-slate-400'}">
            ${STAT_ICONS[key]} <span class="text-xs">${label}</span>
        </button>`).join('');
    modal.classList.remove('hidden');
};

window.selectStat = (key) => {
    state.ui.selectedStat = key;
    const btns = document.querySelectorAll('.stat-btn');
    btns.forEach(btn => {
        if(btn.innerHTML.includes(STAT_ICONS[key])) btn.className = "stat-btn p-2 text-sm rounded-lg border flex flex-col items-center gap-1 transition-all bg-[#ff6b35] border-[#ff6b35] text-white";
        else btn.className = "stat-btn p-2 text-sm rounded-lg border flex flex-col items-center gap-1 transition-all bg-slate-950 border-slate-700 text-slate-400";
    });
};

window.closeModal = () => document.getElementById('habit-modal').classList.add('hidden');
